import type { Drill } from "./types";

// Education / mid drills, keyed by module slug — 25 per module.
// Experienced teacher / department head / senior trainer: parent conferences,
// proposals to administration, mentoring newer teachers, department meetings,
// student advocacy, and staff PD. Merged into course.ts.
export const EDUCATION_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-edu-mid-01","level":"mid","profession":"education","title":"The buried meeting request","scenario":"You need the principal to move your department meeting to Thursday so the new co-teacher can attend. Your draft email opens with two paragraphs about how valuable her perspective would be before the actual request appears.","task":"Rewrite the email so the request and the reason land in the first sentence.","tips":["Lead with the ask: move the meeting to Thursday.","One clause of reason is enough up front.","Cut the warm-up about how valuable it would be — the ask implies it."],"focus":["clarity","concision"],"placeholder":"Could we move Tuesday's department meeting to Thursday so Ms. Alvarez can attend?"},
    {"id":"lead-edu-mid-02","level":"mid","profession":"education","title":"The failing-grade email","scenario":"A parent emailed asking how their son is doing in your class. He is currently at 54% with four missing assignments, and there is still a realistic path to passing. Your draft spends three sentences on how much you enjoy having him in class before the grade appears.","task":"Write a 3-4 sentence reply that states where he stands and the path forward first.","tips":["Sentence one: the current grade and what is driving it.","The plan to recover comes second, warmth third — not the reverse.","Kindness is fine; burying the news is not."],"focus":["clarity","structure"],"placeholder":"Marcus is currently at 54%, mainly because of four missing assignments — and there is still a clear path to passing."},
    {"id":"lead-edu-mid-03","level":"mid","profession":"education","title":"The department meeting opener","scenario":"After weeks of discussion, you have decided the department will use a common final exam this semester. You open the meeting planning to recap all the discussion history before announcing the decision.","task":"Write the first two sentences of the meeting, leading with the decision.","tips":["State the decision in sentence one — the room already knows the history.","Sentence two: what happens next and by when.","Save the reasoning for questions, not the opening."],"focus":["structure","impact"]},
    {"id":"lead-edu-mid-04","level":"mid","profession":"education","title":"The counselor flag","scenario":"A usually reliable tenth grader has missed six of your last ten classes and stopped turning in work. You are messaging the counselor, but your draft narrates the whole timeline before naming what you need.","task":"Write a 2-3 sentence message that leads with the concern and the ask.","tips":["First sentence: the student, the change, and that you want a check-in.","The timeline detail is support — one sentence, after the ask.","Say what you will do on your end so it reads as a partnership."],"focus":["clarity","impact"],"placeholder":"I'd like you to check in with Jordan Reyes — he's missed six of my last ten classes and stopped submitting work."},
    {"id":"lead-edu-mid-05","level":"mid","profession":"education","title":"The yes/no the principal asked","scenario":"The principal emailed one question: can your department absorb an extra section of ninth-grade English next year? You know the answer is yes, with one condition about planning time. Your draft opens with enrollment history instead of the answer.","task":"Write a reply that answers yes or no in the first sentence, then the condition.","tips":["Answer the actual question in the first three words.","One condition, stated plainly, comes second.","Enrollment context only if it changes the decision."],"focus":["concision","clarity"],"placeholder":"Yes — we can absorb the section, with one condition:"},
    {"id":"lead-edu-mid-06","level":"mid","profession":"education","title":"The field trip proposal","scenario":"You want approval for a museum trip for 60 students on May 14: two buses, $840 total, three chaperones already lined up. Your draft to the assistant principal starts with the curriculum connections before the request.","task":"Write an opening that puts the approval request, date, and cost in the first sentence.","tips":["Approvers scan for the ask, the date, and the number — give all three up front.","Curriculum alignment is the supporting paragraph.","Flag what is already handled so the approval feels easy."],"focus":["clarity","structure"],"placeholder":"Requesting approval for a May 14 museum trip: 60 students, two buses, $840 total."},
    {"id":"lead-edu-mid-07","level":"mid","profession":"education","title":"The pilot update that hides the result","scenario":"The principal asked how the new writing curriculum pilot is going. The headline: on-time essay completion is up from 68% to 88% across your two pilot sections. Your draft opens with how the units were sequenced.","task":"Write a 2-3 sentence update that leads with the result.","tips":["The number is the news — put it in sentence one.","How you got there is the second sentence, briefly.","End with what you recommend or need next."],"focus":["impact","precision"]},
    {"id":"lead-edu-mid-08","level":"mid","profession":"education","title":"The observation note with one point","scenario":"You observed a second-year teacher's class as her mentor. There is one thing that matters most: her directions come after she hands out materials, so students stop listening. Your draft note lists eleven small observations first.","task":"Write a note that leads with the one change that matters most.","tips":["One main point, stated first — the rest can wait for the debrief.","Name the behavior and its effect on students, not a general impression.","A single clear priority is a gift; eleven notes are noise."],"focus":["clarity","impact"],"placeholder":"One thing to try tomorrow: give directions before you hand out materials."},
    {"id":"lead-edu-mid-09","level":"mid","profession":"education","title":"The deadline change announcement","scenario":"Progress-report grades are now due Wednesday at noon instead of Friday, because the office moved the mailing date. You are emailing your department, and your draft opens with an apology and the backstory.","task":"Write a 1-2 sentence announcement that leads with the new deadline.","tips":["New date and time in the first five words.","One clause of why — teachers deserve the reason, not the saga.","Bold or repeat the date if the channel allows it."],"focus":["concision","clarity"],"placeholder":"Progress-report grades are now due Wednesday at noon —"},
    {"id":"lead-edu-mid-10","level":"mid","profession":"education","title":"The coverage swap ask","scenario":"You need a colleague to cover your third-period class next Tuesday so you can attend an IEP meeting, and you can cover her Friday duty in exchange. Your draft spends a paragraph explaining the IEP scheduling mess first.","task":"Write a message that leads with the swap you are proposing.","tips":["The whole trade in sentence one: what you need, what you offer.","Why is one clause, not a paragraph.","Make yes easy: date, period, and room all in the first two lines."],"focus":["clarity","concision"]},
    {"id":"lead-edu-mid-11","level":"mid","profession":"education","title":"The supply budget request","scenario":"Your science department needs $1,200 for lab consumables before the spring units: goggles, reagents, and replacement glassware. Your draft to the principal opens with a history of past budget cycles.","task":"Write an opening that leads with the amount, what it buys, and when it is needed.","tips":["Lead with the number and the deadline — that is the decision.","Three categories of spend, one line each, right after.","History of past budgets only if asked."],"focus":["structure","precision"],"placeholder":"Requesting $1,200 for spring lab consumables, needed by March 1:"},
    {"id":"lead-edu-mid-12","level":"mid","profession":"education","title":"The incident summary","scenario":"Two students had a shoving match in the hallway outside your room between periods. Both are fine, both are in the office, and you separated them within seconds. Your written summary for the assistant principal starts with what class you were teaching.","task":"Write a 2-3 sentence summary that leads with what happened and the current status.","tips":["First sentence: the event, the students, the outcome.","Status now — where they are, who has them — comes immediately after.","Chronology of your afternoon is not the headline."],"focus":["clarity","precision"]},
    {"id":"lead-edu-mid-13","level":"mid","profession":"education","title":"The retake decision","scenario":"A parent emailed asking whether their daughter can retake Friday's quiz. Your department policy allows one retake per quarter with a completed corrections sheet, and she qualifies. Your draft explains the whole policy before answering.","task":"Write a reply that gives the answer first, then the one step required.","tips":["Yes or no in sentence one.","The one required step comes second, with its deadline.","Quote the full policy only if it blocks the answer."],"focus":["clarity","concision"],"placeholder":"Yes — Maya can retake the quiz once she submits her corrections sheet, due Thursday."},
    {"id":"lead-edu-mid-14","level":"mid","profession":"education","title":"The reading-program pick","scenario":"The principal asked your department to evaluate two reading intervention programs and recommend one. Your committee clearly prefers Program B. Your draft memo walks through the full comparison matrix before naming the pick.","task":"Rewrite the memo opening so the recommendation comes first, with the top reason attached.","tips":["Name the pick in sentence one, with the single strongest reason.","The comparison matrix becomes supporting evidence below.","A clear recommendation is what was asked for — give it."],"focus":["structure","impact"],"placeholder":"We recommend Program B —"},
    {"id":"lead-edu-mid-15","level":"mid","profession":"education","title":"The curriculum-map slip","scenario":"You committed to finishing the grade 7 curriculum map by Friday, but two team members were out sick and it will now be Wednesday of next week. Your draft to the curriculum director opens with the illness saga.","task":"Write a 2-3 sentence message that states the new date up front.","tips":["Lead with the new date — that is what they must replan around.","Reason in one clause; no one needs the full staffing story.","Say what is already done so the slip has a shape."],"focus":["clarity","impact"]},
    {"id":"lead-edu-mid-16","level":"mid","profession":"education","title":"The PD session opener","scenario":"You are opening a 45-minute staff PD session on checking for understanding. Your slide deck starts with your background, the agenda, and the research history before the actual takeaway appears on slide six.","task":"Write the first two sentences of the session, leading with the takeaway teachers will leave with.","tips":["Open with the one practice they will use tomorrow.","Credibility comes from the content, not a bio slide.","Tell them what they will walk out able to do."],"focus":["impact","audience"],"placeholder":"By the end of these 45 minutes, you'll have three ways to check understanding that take under two minutes each."},
    {"id":"lead-edu-mid-17","level":"mid","profession":"education","title":"The placement fix","scenario":"A student who completed honors prerequisites was scheduled into your standard section by mistake. You are emailing the registrar, and your draft recounts the student's whole academic history before stating the correction needed.","task":"Write a message that leads with the specific change you need.","tips":["First sentence: move this student from section X to section Y.","One sentence of justification — the prerequisite she completed.","Include the exact section codes so it is one action, not a follow-up."],"focus":["clarity","precision"]},
    {"id":"lead-edu-mid-18","level":"mid","profession":"education","title":"The district data reply","scenario":"The district office asked how many students in your department are enrolled in AP courses this year and how that compares to last year. You know it: 118 this year, 94 last year. Your draft opens with caveats about how the data was pulled.","task":"Write a reply that gives both numbers in the first sentence, caveat after.","tips":["Numbers first: 118 this year, up from 94.","One caveat, stated once, after the answer.","They asked a counting question — do not turn it into a report."],"focus":["precision","concision"],"placeholder":"118 students are enrolled in AP courses this year, up from 94 last year."},
    {"id":"lead-edu-mid-19","level":"mid","profession":"education","title":"The accreditation status line","scenario":"You chair the accreditation self-study committee and owe the principal a monthly update. The headline: three of five sections are drafted and you are on track for the March deadline. Your draft opens with committee attendance notes.","task":"Write a 2-3 sentence update that leads with status against the deadline.","tips":["Sentence one: where you are versus the March deadline.","Then the one risk or need, if any.","Committee logistics belong in minutes, not the update."],"focus":["structure","concision"]},
    {"id":"lead-edu-mid-20","level":"mid","profession":"education","title":"The staffing conversation ask","scenario":"You want 20 minutes with the principal to raise a concern about next year's staffing plan for your department before the master schedule is locked. Your draft says 'when you have a moment, I'd love to touch base about some things.'","task":"Write a request that names the topic, the time needed, and the deadline pressure up front.","tips":["Vague requests get deprioritized — name the topic plainly.","Say why timing matters: the schedule locks soon.","Offer two specific windows to make scheduling one reply."],"focus":["clarity","precision"],"placeholder":"Could I get 20 minutes this week to discuss next year's staffing plan before the master schedule locks?"},
    {"id":"lead-edu-mid-21","level":"mid","profession":"education","title":"The broken-tech ticket","scenario":"The projectors in rooms 204 and 206 have been down for three days, and two teachers are rewriting lessons daily to work around it. Your note to IT opens with pleasantries and 'whenever you get a chance.'","task":"Write a request that leads with the impact and the specific fix needed.","tips":["First sentence: what is broken, where, and what it is costing.","Ask for a timeframe, not 'whenever.'","Two room numbers and a symptom make the ticket actionable."],"focus":["impact","precision"]},
    {"id":"lead-edu-mid-22","level":"mid","profession":"education","title":"The follow-up for exam questions","scenario":"A colleague promised her share of the common exam questions last week, and you assemble the full exam on Thursday. Your draft nudge opens with 'sorry to bother you, I know things are crazy.'","task":"Write a follow-up that leads with what you need and the real deadline.","tips":["Lead with the item and the date it is due.","Explain the dependency: assembly happens Thursday.","Skip the apology — a clear ask is not an imposition."],"focus":["clarity","impact"],"placeholder":"Could you send your exam questions by Wednesday? I'm assembling the full exam Thursday morning."},
    {"id":"lead-edu-mid-23","level":"mid","profession":"education","title":"The family announcement","scenario":"Because of a districtwide PD day, school dismisses at 12:30 on Friday and after-school clubs are cancelled. Your draft family message opens with a paragraph about the value of teacher professional development.","task":"Write a 2-sentence announcement that leads with the change families must act on.","tips":["The dismissal time is what changes pickup plans — say it first.","Clubs cancelled is the second fact, not a footnote.","The why is one clause at most; families need logistics, not philosophy."],"focus":["audience","clarity"],"placeholder":"This Friday, school dismisses at 12:30 and after-school clubs are cancelled."},
    {"id":"lead-edu-mid-24","level":"mid","profession":"education","title":"The grades-on-time answer","scenario":"The assistant principal messages you: 'Will your department's grades all be posted by the deadline Friday?' You know 11 of 12 teachers are done, and one needs until Monday for one section. Your draft explains that teacher's situation first.","task":"Write a reply that answers the question in the first sentence, then the one exception.","tips":["Give the verdict first: mostly yes, one exception.","Name the exception precisely — one teacher, one section, Monday.","Say how you are handling it so the exception arrives solved."],"focus":["clarity","precision"],"placeholder":"Yes for 11 of 12 teachers — one section will post Monday, and here's the plan:"},
    {"id":"lead-edu-mid-25","level":"mid","profession":"education","title":"The conference-week handoff","scenario":"You will be at a national conference for three days and a substitute is covering your classes. One thing genuinely matters: fourth period has a lab safety quiz Wednesday that must be proctored exactly as written. Your handoff note opens with general classroom philosophy.","task":"Write a handoff note whose first line is the one thing the substitute must get right.","tips":["If they read one line, it should be the Wednesday quiz.","Routine instructions can follow in a list.","Put contact info for that one scenario next to the headline item."],"focus":["structure","clarity"],"placeholder":"The one thing that matters most: Wednesday, period 4 has a lab safety quiz that must be proctored exactly as written."}
  ],
  "start-with-the-audience": [
    {"id":"audience-edu-mid-01","level":"mid","profession":"education","title":"The rubric explained to parents","scenario":"You are introducing a new writing rubric at back-to-school night. Your draft says students will be assessed on 'claim-evidence-reasoning alignment and command of syntactic variety.' Parents want to know what their child must do and how they can help.","task":"Rewrite the explanation in 2-3 sentences a parent with no teaching background can act on.","tips":["Translate each rubric term into what a student actually does.","Tell parents one concrete way to help at home.","If a term needs defining to survive, replace it."],"focus":["audience","clarity"],"placeholder":"Your child's writing is graded on three things: making a clear point, backing it with evidence, and explaining why the evidence matters."},
    {"id":"audience-edu-mid-02","level":"mid","profession":"education","title":"The sub-friendly accommodation note","scenario":"A substitute is covering your class tomorrow, and three students have accommodations: extended time, preferential seating, and permitted movement breaks. Your draft uses IEP shorthand — '504, ET x1.5, see BIP' — that a guest teacher cannot decode.","task":"Rewrite the note so any substitute knows exactly what to do for each student.","tips":["Write the action, not the acronym: 'give him 15 extra minutes.'","One line per student, in the order they might come up.","Assume the reader has never seen your school's paperwork."],"focus":["audience","precision"]},
    {"id":"audience-edu-mid-03","level":"mid","profession":"education","title":"The board hears the reading data","scenario":"You are presenting reading-growth data to the school board. Your slide says 'median NWEA RIT growth exceeded projected norms in 4 of 6 grade bands.' Board members are community volunteers who care whether kids are learning to read and whether the program is worth its cost.","task":"Rewrite the headline finding in one or two sentences for a board audience.","tips":["Lead with the plain claim: more kids grew more than expected.","Anchor it in something a board member can picture — grade levels, months of growth.","Keep the instrument name off the headline; it can live in the appendix."],"focus":["audience","impact"],"placeholder":"In four of our six grade levels, students grew more in reading this year than national benchmarks predicted."},
    {"id":"audience-edu-mid-04","level":"mid","profession":"education","title":"Standards-based grading, for skeptics","scenario":"Your school is moving to standards-based grading, and you are writing the parent letter. Your draft leads with 'decoupling formative assessment from summative reporting.' The parents most worried are the ones asking: will this hurt my kid's GPA and college applications?","task":"Write a 3-4 sentence explanation that answers the worried parent's real question first.","tips":["Name the fear and answer it before explaining the system.","Translate 'standards-based' into what the report card will literally show.","One benefit for the student, stated concretely, beats three abstractions."],"focus":["audience","clarity"]},
    {"id":"audience-edu-mid-05","level":"mid","profession":"education","title":"The two-minute principal version","scenario":"You spent six weeks piloting flexible seating and have pages of observations. The principal stops you in the hall: 'How's the seating pilot going?' She has two minutes and one real question — should the school invest in this?","task":"Give a 2-3 sentence answer pitched at what she needs to decide.","tips":["Answer the investment question, not the research question.","One number and one caveat is the right density for a hallway.","Offer the full write-up as a follow-up, not a download."],"focus":["audience","concision"],"placeholder":"Worth expanding to one more grade, not the whole school yet —"},
    {"id":"audience-edu-mid-06","level":"mid","profession":"education","title":"The curriculum change, told to students","scenario":"Your department is replacing the semester research paper with a staged portfolio. You drafted the announcement for students, but it reads like the memo you sent administration — 'scaffolded milestones aligned to revised standards.' Students want to know: what do I have to do and is it harder?","task":"Rewrite the announcement in 2-3 sentences in language that answers what students actually care about.","tips":["Say what changes in their week, not in the standards document.","Answer 'is this more work?' honestly and early.","One reason it helps them — feedback before the grade — lands better than five."],"focus":["audience","clarity"]},
    {"id":"audience-edu-mid-07","level":"mid","profession":"education","title":"The acronym-free onboarding note","scenario":"A first-year teacher joins your department mid-semester. Your welcome note is full of local shorthand: 'MTSS referrals go through the SST after Tier 2 documentation in the LMS.' She has been in the building for two days.","task":"Rewrite one paragraph of onboarding so a brand-new teacher can follow it without a glossary.","tips":["Spell out every acronym the first time or drop it.","Describe the action in people terms: who to email, where to click.","The curse of knowledge is strongest about your own building's routines."],"focus":["audience","clarity"],"placeholder":"When a student needs extra support, here's the path: first, document what you've tried —"},
    {"id":"audience-edu-mid-08","level":"mid","profession":"education","title":"The plain-language family letter","scenario":"You are writing home about a reading intervention placement. Many families at your school speak English as a second language, and your draft uses phrases like 'diagnostic benchmarking indicates a need for supplemental phonics instruction.'","task":"Rewrite the key message in 2-3 short sentences using plain, direct language.","tips":["Short sentences, common words, active voice.","Lead with what will happen and that it is good support, not a punishment.","Read it aloud — if a sentence takes two breaths, split it."],"focus":["audience","clarity"],"placeholder":"Starting next week, your child will get extra reading help in a small group, four days a week."},
    {"id":"audience-edu-mid-09","level":"mid","profession":"education","title":"The tech pitch to a veteran","scenario":"You are helping roll out a new gradebook tool. A 28-year veteran colleague is openly unenthusiastic. Your draft email lists features — 'API-synced rosters, customizable weighting schemas.' What he cares about: will this cost me time, and will it break in week three?","task":"Write a 2-3 sentence pitch aimed at what this specific colleague values.","tips":["Lead with the time math: what it saves versus what setup costs.","Address reliability directly — his real objection is churn, not technology.","One offer of concrete help beats a feature list."],"focus":["audience","impact"]},
    {"id":"audience-edu-mid-10","level":"mid","profession":"education","title":"The newsletter blurb","scenario":"Your class is starting a project-based unit where students design a community garden proposal. The family newsletter draft opens with 'students will engage in authentic interdisciplinary inquiry.' Families skim this newsletter on their phones.","task":"Write a 2-sentence blurb that makes a skimming parent understand and care.","tips":["Say what kids will actually make and do.","Give families one thing to ask their child about at dinner.","Phone-skimmable: concrete nouns, no education-speak."],"focus":["audience","concision"],"placeholder":"This month, students are designing a real proposal for a community garden —"},
    {"id":"audience-edu-mid-11","level":"mid","profession":"education","title":"Same news, different room","scenario":"The state changed its testing window, compressing your review time by two weeks. You already wrote the version for administration, full of compliance language. Now you must tell your department, who care about one thing: what does this do to my pacing?","task":"Write the 2-3 sentence teacher-facing version of the same news.","tips":["Lead with the impact on their calendar, not the state's rationale.","Give the new key dates immediately.","Say what the department will do about the lost time — that is the real message."],"focus":["audience","structure"]},
    {"id":"audience-edu-mid-12","level":"mid","profession":"education","title":"The referral the counselor can use","scenario":"You are referring a student to the counselor for anxiety you have observed around tests. Your draft is a page of narrative. The counselor triages dozens of referrals and needs: what you observed, when it started, what you have tried, and how urgent it is.","task":"Rewrite the referral in 3-4 sentences organized around what the counselor needs to act.","tips":["Structure around her checklist: observed, since when, tried, urgency.","Observable behavior, not diagnosis — 'left the room before two quizzes,' not 'has anxiety.'","State your urgency read plainly so she can triage."],"focus":["audience","precision"]},
    {"id":"audience-edu-mid-13","level":"mid","profession":"education","title":"The budget reality, kindly","scenario":"The principal told you the department budget is flat next year despite rising enrollment. You must relay this at the department meeting. Your draft leads with district finance mechanics; your teachers just want to know what they can and cannot count on.","task":"Write a 3-sentence version for your department that leads with what it means for them.","tips":["Translate 'flat budget' into their terms: what gets funded, what waits.","Do not perform the district's reasoning — own the message for your room.","End with the one place their input shapes the outcome."],"focus":["audience","clarity"],"placeholder":"Our budget stays flat next year, so here's what that means in practice:"},
    {"id":"audience-edu-mid-14","level":"mid","profession":"education","title":"The elective pitch at the course fair","scenario":"You have 90 seconds at the course fair to pitch your new media literacy elective to tenth graders. Your draft describes learning objectives. Students choosing electives ask different questions: is it interesting, is it useful, how hard is it?","task":"Write a 3-sentence pitch aimed at what a fifteen-year-old actually weighs.","tips":["Open with what they will do, not what they will learn.","Answer the workload question before they ask it.","One vivid project beats a list of topics."],"focus":["audience","impact"]},
    {"id":"audience-edu-mid-15","level":"mid","profession":"education","title":"The behavior plan for the para","scenario":"A paraprofessional supports a student with a behavior plan in your class. The plan document is four pages of clinical language. She needs to know: what to watch for, what to do in the moment, and what to leave to you.","task":"Write a 3-4 sentence working summary for the paraprofessional.","tips":["Organize by her moments: early warning signs, in-the-moment response, escalation.","Use the words she would say and the actions she would take.","Be explicit about the boundary: what is her call and what is yours."],"focus":["audience","structure"],"placeholder":"Here's the short version of Devon's plan for our class: watch for —"},
    {"id":"audience-edu-mid-16","level":"mid","profession":"education","title":"The local business ask","scenario":"You are writing to a local hardware store asking them to donate materials for your engineering club. Your draft explains your curriculum standards. The owner cares about cost, effort, and whether it visibly helps local kids.","task":"Write a 3-4 sentence request framed around what the business owner values.","tips":["Lead with the concrete ask: what materials, roughly what value.","Make the community benefit visible: named club, real kids, public showcase.","Make saying yes effortless — you pick up, they get thanked publicly."],"focus":["audience","impact"]},
    {"id":"audience-edu-mid-17","level":"mid","profession":"education","title":"Anecdotes into administration's language","scenario":"Your monthly report to administration on the mentoring program is full of warm anecdotes about your two mentees. Administration reads these reports for evidence: retention risk, instructional growth, compliance with the induction requirements.","task":"Rewrite one anecdote as a 2-sentence report line administration can use.","tips":["Convert the story into a status: on track, improving, at risk.","Keep one concrete detail as evidence — it earns the claim.","Ask what decision the reader makes with this report, and feed that."],"focus":["audience","precision"],"placeholder":"Both mentees are on track against induction benchmarks; one example —"},
    {"id":"audience-edu-mid-18","level":"mid","profession":"education","title":"The survey results, back to staff","scenario":"You ran the staff PD feedback survey and are reporting results at the next staff meeting. Your draft leads with response rates and methodology. Staff want to know: did anyone listen, and what will change?","task":"Write a 2-3 sentence summary that leads with what staff said and what changes as a result.","tips":["Lead with the top finding in staff's own words.","Pair every finding with a response: change, keep, or explain.","Methodology earns one clause, at most."],"focus":["audience","impact"]},
    {"id":"audience-edu-mid-19","level":"mid","profession":"education","title":"Formative assessment for a volunteer","scenario":"A parent volunteer helping in your classroom asks why you give so many little quizzes that 'don't count.' You start to explain retrieval practice and formative assessment theory, and her eyes glaze.","task":"Explain the practice in 2 sentences a volunteer will understand and repeat correctly.","tips":["Use an analogy from everyday life — practice reps, not grades.","The key distinction: these find gaps before the test that counts.","If she can re-explain it to another parent, you succeeded."],"focus":["audience","clarity"],"placeholder":"Those little quizzes are practice reps, not grades —"},
    {"id":"audience-edu-mid-20","level":"mid","profession":"education","title":"One email, one primary audience","scenario":"You drafted one email about the new late-work policy addressed to both families and your department. It serves neither: too procedural for parents, too explanatory for teachers. You have been told to send one message.","task":"Choose the primary audience, name it, and rewrite the first 2 sentences for that reader.","tips":["Pick the audience whose behavior must change most — write to them.","The secondary audience gets a separate short note or a forwardable summary.","A message for everyone is a message for no one."],"focus":["audience","structure"]},
    {"id":"audience-edu-mid-21","level":"mid","profession":"education","title":"The placement call, to an anxious parent","scenario":"You recommended a student repeat Algebra 1 rather than move on, and the parent requested a meeting. Your prepared explanation is built on scope-and-sequence logic. The parent's actual questions: is my child behind forever, and did we fail her?","task":"Write your 3-sentence opening for the meeting, aimed at the parent's real concerns.","tips":["Answer the fear first: this is a path forward, not a verdict.","Then the concrete plan and what stays open to her later.","Curriculum logic is your evidence, not your opener."],"focus":["audience","clarity"],"placeholder":"I want to start with the most important thing: this decision keeps every door open for Sofia."},
    {"id":"audience-edu-mid-22","level":"mid","profession":"education","title":"The facilities request that gets scheduled","scenario":"Your classroom needs an outlet moved and two bookshelves anchored before you can set up the new small-group area. Your draft to facilities describes your instructional vision. The facilities team schedules jobs by location, task, and access time.","task":"Rewrite the request in the terms the facilities team plans by.","tips":["Room number, exact tasks, and when the room is empty — that is their language.","One line on why only if it affects priority.","Two clear tasks get scheduled; a vision paragraph gets skipped."],"focus":["audience","precision"]},
    {"id":"audience-edu-mid-23","level":"mid","profession":"education","title":"Accreditation, minus the dread","scenario":"You are briefing your department on what the accreditation visit means for them. The official documentation is dense and ominous. Your teachers need to know: what will visitors do, what should I have ready, and am I being evaluated?","task":"Write a 3-4 sentence briefing organized around those three questions.","tips":["Answer 'am I in trouble?' first — no, and here is what it actually is.","Concrete expectations: what a visitor might ask, what to have on the wall.","Calibrate the altitude: they need their part, not the whole framework."],"focus":["audience","structure"],"placeholder":"First, the reassurance: the visitors are evaluating our program, not you as individuals."},
    {"id":"audience-edu-mid-24","level":"mid","profession":"education","title":"The syllabus students actually read","scenario":"Your course syllabus opens with a 200-word course description written for the curriculum office. Students read syllabi looking for: what we do, how grading works, and what gets me in trouble.","task":"Rewrite the syllabus opening in 3 sentences addressed to students.","tips":["Write to 'you,' not 'students will.'","Lead with what the class is like week to week.","Save the standards alignment for the version the office files."],"focus":["audience","clarity"]},
    {"id":"audience-edu-mid-25","level":"mid","profession":"education","title":"The homework policy, in public","scenario":"Your school reduced nightly homework, and a community social media group is debating it, with some parents saying the school is lowering standards. The principal asked you to draft a short public post. The primary audience is worried parents, not the loudest critics.","task":"Write a 3-sentence post addressed to the worried parent in the middle.","tips":["Write for the persuadable reader, not the angriest one.","Lead with what stays rigorous, then what changed and why it helps their child.","Calm, concrete, and unhedged — public posts get screenshotted."],"focus":["audience","impact"]}
  ],
  "structure-that-carries": [
    {"id":"structure-edu-mid-01","level":"mid","profession":"education","title":"Twelve parent concerns, three buckets","scenario":"After a week of parent-teacher conferences you have twelve sticky notes of concerns: homework load, unclear grading, bus timing, reading levels, phone use, and seven more. You are summarizing them for the principal, and a flat list of twelve will not get read.","task":"Group the concerns into 3 named buckets and write the one-sentence governing summary.","tips":["Find the natural categories: academics, communication, logistics often emerge.","Name each bucket by the theme, not the loudest example.","The governing sentence should tell the principal what the twelve add up to."],"focus":["structure","clarity"],"placeholder":"Conference feedback clustered into three themes: workload, grading transparency, and logistics."},
    {"id":"structure-edu-mid-02","level":"mid","profession":"education","title":"SCQA for the curriculum proposal","scenario":"You are proposing that administration fund a new phonics curriculum for grades K-2. You have the evidence, but your draft memo opens with vendor details. You want the classic frame: Situation, Complication, Question, Answer.","task":"Write the 4-sentence SCQA opening for the proposal.","tips":["Situation: the stable fact everyone agrees on — current reading outcomes.","Complication: what changed or is failing — the gap the data shows.","Question and Answer: what should we do, and your one-sentence recommendation.","Each element is one sentence; the detail hangs below."],"focus":["structure","impact"],"placeholder":"Our K-2 students learn to read with a curriculum adopted nine years ago. This year, 40% of second graders..."},
    {"id":"structure-edu-mid-03","level":"mid","profession":"education","title":"PREP on block scheduling","scenario":"In a staff meeting, the principal turns to you: 'You taught under block scheduling at your last school — what do you think of it for us?' Thirty colleagues are watching. You have an informed view but no notes.","task":"Give a PREP answer aloud: Point, Reason, Example, Point — in under 60 seconds.","tips":["State your point in the first sentence, even if it is qualified.","One reason and one lived example from your last school — not four.","Restate the point at the end so it is what the room remembers."],"focus":["structure","clarity"]},
    {"id":"structure-edu-mid-04","level":"mid","profession":"education","title":"The debrief with a spine","scenario":"You are debriefing a new teacher after observing her class. You have notes on pacing, transitions, questioning, board work, and student talk. Delivered as a list, it will overwhelm her. You need one governing idea with at most three supporting points.","task":"Write the governing sentence and the 3 points beneath it.","tips":["Find what the notes have in common — often one root cause explains most.","Three points maximum; park the rest for later debriefs.","Each point should be something she can act on this week."],"focus":["structure","impact"],"placeholder":"Almost everything I noted traces to one lever: how you open each activity."},
    {"id":"structure-edu-mid-05","level":"mid","profession":"education","title":"The agenda that runs itself","scenario":"Your department meeting topics arrived as a messy list: exam schedule, new copier codes, a student concern, curriculum mapping, textbook returns, PD sign-ups. Forty-five minutes, eight teachers, and last month's meeting ran over on trivia.","task":"Organize the list into a structured agenda: decisions first, discussions second, announcements last, with times.","tips":["Sort by what needs the room: decisions and discussion get live minutes.","Announcements go to email or the last five minutes.","Put a time and an owner on every item — structure is a fence against drift."],"focus":["structure","concision"]},
    {"id":"structure-edu-mid-06","level":"mid","profession":"education","title":"The grant narrative skeleton","scenario":"You are applying for a $5,000 literacy grant. The application asks for a project narrative, and your draft is one long paragraph mixing need, plan, and outcomes. Reviewers score dozens of these against a rubric.","task":"Write the 3-sentence skeleton: the need, the plan, the measurable outcome.","tips":["One sentence per element — the paragraph grows from this spine.","Mirror the funder's own rubric categories in your ordering.","The outcome sentence should contain a number a reviewer can circle."],"focus":["structure","precision"],"placeholder":"One in three of our fourth graders reads below grade level. This grant funds..."},
    {"id":"structure-edu-mid-07","level":"mid","profession":"education","title":"Pyramid the pilot report","scenario":"Your report on the math intervention pilot has eleven findings in the order you discovered them. The principal will read the first paragraph and skim the rest. The findings support one conclusion: the pilot works for grade 6 but not grade 8.","task":"Write the governing conclusion and group the findings into 2-3 supporting buckets.","tips":["The conclusion goes first — readers should never assemble it themselves.","Group findings by what they prove, not when you found them.","A finding that supports nothing gets cut or footnoted."],"focus":["structure","clarity"]},
    {"id":"structure-edu-mid-08","level":"mid","profession":"education","title":"Data themes for the data team","scenario":"You pulled quarter grades, attendance, and assessment scores for your grade level and found scattered patterns: Friday absences up, quiz scores dip after long weekends, two classes outperforming. The data team meeting needs themes, not a data dump.","task":"Group your observations into 2-3 named themes and write a headline for each.","tips":["A theme is a claim, not a category: 'attendance is driving the dips,' not 'attendance data.'","Each headline should survive alone on a slide.","Two strong themes beat five weak ones — cut the orphan observations."],"focus":["structure","precision"]},
    {"id":"structure-edu-mid-09","level":"mid","profession":"education","title":"SCQA opens the PD session","scenario":"You are leading staff PD on retrieval practice. Your current opening: 'Today we're going to talk about retrieval practice.' Flat. You want teachers leaning in within four sentences.","task":"Write an SCQA opening for the session.","tips":["Situation: something every teacher in the room recognizes — reviewing before the test.","Complication: the research says that common approach fades fast.","The question should be the one they now want answered; your session is the answer."],"focus":["structure","audience"],"placeholder":"We all review before tests — and our students still forget by June. What if the problem is when we ask, not how often?"},
    {"id":"structure-edu-mid-10","level":"mid","profession":"education","title":"Parent night in three moves","scenario":"You have fifteen minutes at curriculum night to cover your entire year: units, grading, homework, communication, field trips, and how families can help. Last year you ran out of time on slide nine of twenty.","task":"Structure the talk as one governing message with 3 sections, and write the opening sentence.","tips":["Decide the one thing every parent must leave knowing — that is the spine.","Three sections, announced up front, so parents can follow the map.","Anything not serving the spine goes to the handout."],"focus":["structure","audience"]},
    {"id":"structure-edu-mid-11","level":"mid","profession":"education","title":"The evidence binder that argues","scenario":"For the accreditation self-study you have forty artifacts: lesson plans, meeting minutes, student work, PD certificates. Dumped in a binder chronologically, they prove nothing. Each standard needs evidence organized as an argument.","task":"For one standard, write the claim sentence and name the 3 categories of evidence beneath it.","tips":["Lead with the claim the evidence must prove, then sort under it.","Categories mirror the standard's own language — make the reviewer's job effortless.","An artifact that proves nothing for this claim moves to another section or out."],"focus":["structure","clarity"]},
    {"id":"structure-edu-mid-12","level":"mid","profession":"education","title":"PREP for the homework question","scenario":"At conferences, a parent asks — a little sharply — 'Why does my daughter have so much homework in your class?' You have a real answer about practice and feedback, but under mild confrontation you tend to ramble.","task":"Give a PREP answer aloud in 30-45 seconds: Point, Reason, Example, Point.","tips":["Point first: the homework is practice with a purpose, and here it is.","Your example should be from her daughter's actual work if you can.","Landing back on the point keeps the answer from trailing into apology."],"focus":["structure","audience"],"placeholder":"Fair question. Every assignment I send home is practice for a specific skill — here's how it works."},
    {"id":"structure-edu-mid-13","level":"mid","profession":"education","title":"The year-end report spine","scenario":"Your end-of-year department report covers staffing, results, curriculum work, PD, and next year's needs. Last year's version was eight pages nobody finished. The principal forwards these to the superintendent's office.","task":"Write the one-paragraph executive summary: governing sentence plus one sentence per section.","tips":["The governing sentence answers: what kind of year was it, and what do we need?","One sentence per section, each carrying its section's single headline.","Write the summary last but place it first."],"focus":["structure","concision"]},
    {"id":"structure-edu-mid-14","level":"mid","profession":"education","title":"The mentoring plan in three strands","scenario":"You are mentoring a new teacher this year and your support ideas are a jumble: modeling lessons, co-planning, observation cycles, gradebook help, parent-email coaching, classroom-management reading. She needs a plan she can see the shape of.","task":"Organize the support into 3 named strands and write a one-sentence purpose for each.","tips":["Strands by goal, not activity: instruction, systems, communication is one natural cut.","Each strand's purpose sentence says what success looks like by June.","A visible structure lets her ask for what she needs by name."],"focus":["structure","clarity"],"placeholder":"Our year has three strands: your instruction, your systems, and your communication with families."},
    {"id":"structure-edu-mid-15","level":"mid","profession":"education","title":"One idea, three reasons","scenario":"You are proposing a new forensic science elective to the curriculum committee. Your draft email lists nine assorted arguments: student interest, lab equipment already owned, cross-curricular ties, enrollment trends, a colleague certified to teach it, and more.","task":"Write the proposal opening: the governing recommendation plus exactly 3 grouped reasons.","tips":["Nine arguments compete; three grouped reasons compound.","Fold minor points into the reason they support — 'equipment owned' belongs under low cost.","Order reasons by what the committee weighs most: demand, cost, capacity."],"focus":["structure","impact"]},
    {"id":"structure-edu-mid-16","level":"mid","profession":"education","title":"PD feedback into themes","scenario":"Sixty staff wrote open-ended comments about this year's PD. You have everything from 'more time to actually plan' to 'the October speaker was great' to 'stop scheduling PD on Fridays.' The leadership team wants a synthesis, not sixty quotes.","task":"Group the comments into 3 themes and write a headline sentence for each.","tips":["Cluster by underlying need, not by topic word — three complaints may share one root.","Headline each theme as a finding: 'Staff want PD time converted to planning time.'","Keep one vivid quote per theme as the human evidence."],"focus":["structure","precision"]},
    {"id":"structure-edu-mid-17","level":"mid","profession":"education","title":"SCQA for co-teaching","scenario":"You want administration to approve a co-teaching model for the inclusion sections next year. It requires master-schedule changes, so the ask is real. Your instinct is to open with the research literature.","task":"Write the 4-sentence SCQA that opens the proposal.","tips":["Situation: how inclusion sections are staffed today.","Complication: the specific strain — one teacher, widest range of needs, thinnest support.","Your Answer sentence must name the ask: two co-taught sections, which periods."],"focus":["structure","impact"]},
    {"id":"structure-edu-mid-18","level":"mid","profession":"education","title":"Talking points that hold under stress","scenario":"Tomorrow's conference is with parents who dispute their son's plagiarism consequence. You know these meetings can spiral. You want a one-page structure: your opening, the three things you must communicate, and your close.","task":"Write the structured talking points: opening sentence, 3 must-land points, closing sentence.","tips":["Sequence for the listener: what happened, what the policy says, what happens next.","Each point is one sentence you could say verbatim under pressure.","A written structure is what keeps a hard meeting from becoming an argument."],"focus":["structure","clarity"],"placeholder":"Opening: We're here because we caught something early enough to fix it."},
    {"id":"structure-edu-mid-19","level":"mid","profession":"education","title":"The rollout message map","scenario":"The new curriculum map goes live next semester and you own the communication: teachers need training dates, families need a heads-up, and the office needs compliance confirmation. One scattered email thread is how this usually goes wrong.","task":"Sketch the message map: for each of the 3 audiences, the single governing message in one sentence.","tips":["One sentence per audience — if you cannot compress it, the plan is not clear yet.","Sequence matters: teachers hear it before families do.","Each message names an action and a date, not just information."],"focus":["structure","audience"]},
    {"id":"structure-edu-mid-20","level":"mid","profession":"education","title":"Two minutes at the podium","scenario":"You are giving public comment to the school board supporting the arts budget. You get exactly two minutes and a timer. Unstructured passion gets cut off mid-sentence; you have seen it happen.","task":"Write the 2-minute comment using PREP: Point, Reason, Example, Point.","tips":["Your first sentence is the whole argument — assume the timer dies early.","One reason with a number, one example with a name (with permission).","Rehearse the final sentence; boards remember clean endings."],"focus":["structure","impact"],"placeholder":"I'm asking you to keep the arts budget whole, and I'll give you one number and one student."},
    {"id":"structure-edu-mid-21","level":"mid","profession":"education","title":"The recommendation letter that carries","scenario":"You are writing a college recommendation for a strong student. Your draft is chronological — freshman year onward — and reads like a transcript with adjectives. Admissions readers spend ninety seconds per letter.","task":"Restructure: write the governing claim about the student and the 3 qualities that prove it.","tips":["Open with the one-sentence verdict a reader could quote in committee.","Three qualities, each with one specific story — not a tour of four years.","Chronology serves you; claims serve her."],"focus":["structure","impact"]},
    {"id":"structure-edu-mid-22","level":"mid","profession":"education","title":"Interventions in tiers","scenario":"A student is struggling and the support meeting is Friday. Your notes list everything anyone suggested: seat change, reading group, counselor check-ins, tutoring, parent contact log, modified assignments. Presented flat, the family will hear chaos.","task":"Organize the options into 3 escalating tiers and write one sentence introducing the structure.","tips":["Tier by intensity: classroom moves first, targeted support second, formal evaluation last.","The intro sentence tells the family there is a plan with an order, not a grab bag.","Name what triggers moving to the next tier."],"focus":["structure","clarity"],"placeholder":"We have a three-level plan, and we start with the lightest touch:"},
    {"id":"structure-edu-mid-23","level":"mid","profession":"education","title":"The drill announcement that answers in order","scenario":"Lockdown drill procedures changed and you are writing the staff email. Your draft mixes the why, the new steps, the old steps for contrast, and the date. Under stress, staff will reread this email looking for one thing: what do I do.","task":"Restructure the email: what changes, what you do now step by step, effective when.","tips":["Order by the reader's need: action steps before rationale.","Number the steps — prose hides procedures.","Cut the old procedure entirely; contrast breeds confusion in an emergency."],"focus":["structure","clarity"]},
    {"id":"structure-edu-mid-24","level":"mid","profession":"education","title":"The case for the program","scenario":"The after-school tutoring program you coordinate is on the cut list. You get one page to the principal to argue for it. You have usage data, grade impact, family testimony, and cost figures — currently in no particular order.","task":"Write the one-page structure: governing claim, 3 argument buckets, and the close.","tips":["The claim pairs value with cost: what the school gets per dollar.","Buckets: results, reach, and cost-effectiveness is a natural frame.","Close with the decision you are asking for, restated in one line."],"focus":["structure","impact"]},
    {"id":"structure-edu-mid-25","level":"mid","profession":"education","title":"The handoff document","scenario":"A colleague is leaving mid-year and you are absorbing the transition. She offered to 'write everything down,' which historically means eight pages of stream of consciousness. You are giving her a structure to fill in.","task":"Design the handoff structure: 3-4 named sections in the order the incoming teacher will need them.","tips":["Order by urgency: week one survival, then ongoing routines, then background.","Each section gets a one-line description of what belongs in it.","A good structure makes the writer concise for you."],"focus":["structure","concision"],"placeholder":"Section 1 — First two weeks: anything with a date attached."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-edu-mid-01","level":"mid","profession":"education","title":"The hedge-heavy parent email","scenario":"Your draft to a parent reads: 'I just wanted to quickly reach out because I've been noticing that Emma has perhaps been having a somewhat harder time staying focused, and I thought it might possibly be worth mentioning.' One real sentence is hiding in there.","task":"Rewrite the message in 1-2 direct, warm sentences.","tips":["Cut 'just wanted to reach out' — the email is the reaching out.","One hedge maximum; 'perhaps somewhat possibly' is three.","Direct and warm are not opposites."],"focus":["concision","clarity"],"placeholder":"I've noticed Emma having a harder time staying focused this month, and I wanted you to know early."},
    {"id":"concise-edu-mid-02","level":"mid","profession":"education","title":"The syllabus policy diet","scenario":"Your late-work policy runs 140 words, with three restatements and a paragraph anticipating every objection. Students do not read it, which defeats the purpose of a policy.","task":"Cut the policy to 40 words or fewer without losing a rule.","tips":["State each rule once; repetition signals insecurity, not emphasis.","Cut pre-emptive justifications — a clear rule defends itself.","If students can recite it after one read, it is short enough."],"focus":["concision","precision"]},
    {"id":"concise-edu-mid-03","level":"mid","profession":"education","title":"Six sentences to two","scenario":"Your staff-meeting announcement about the new copier codes runs six sentences, including the history of the old codes, an apology for the change, and a joke about the copier. The information content is two facts: new codes, where to get yours.","task":"Cut the announcement to 2 sentences.","tips":["Find the facts first, then delete everything that is not one.","The apology and the joke cost more attention than they buy goodwill.","Announcements are read at a glance or not at all."],"focus":["concision","clarity"]},
    {"id":"concise-edu-mid-04","level":"mid","profession":"education","title":"Feedback without the bubble wrap","scenario":"Your written feedback to a mentee reads: 'You might want to maybe think about possibly trying to consider giving students a bit more wait time after questions.' The suggestion is good; the wrapping makes it optional.","task":"Rewrite the feedback in one clear, kind sentence.","tips":["'Try X' is kinder than five hedges — it respects her ability to hear it.","Keep one softener at most if the relationship needs it.","Vague feedback is the most common way mentors fail new teachers."],"focus":["concision","impact"],"placeholder":"Try counting three seconds of wait time after each question —"},
    {"id":"concise-edu-mid-05","level":"mid","profession":"education","title":"The nominalization purge","scenario":"Your curriculum proposal says: 'The implementation of the utilization of formative assessment strategies will result in the facilitation of improvement in student comprehension.' Somewhere in there, teachers check understanding and students learn more.","task":"Rewrite the sentence with people doing verbs.","tips":["Every '-tion of' hides a verb — dig it out: implement, use, improve.","Name the actor: teachers do the checking, students do the learning.","Read it aloud; if you would never say it, do not write it."],"focus":["concision","clarity"],"placeholder":"When teachers check understanding during lessons, students learn more."},
    {"id":"concise-edu-mid-06","level":"mid","profession":"education","title":"The newsletter nobody finishes","scenario":"Your weekly family newsletter runs 600 words and open rates show most families stop after the first section. Everything in it is 'important' — which is the problem.","task":"Cut this week's edition to 200 words: pick what survives and rewrite the opening.","tips":["Rank items by what a family must act on; the rest links out or waits.","One sentence per item is a discipline worth forcing.","Shorter every week beats longer and unread."],"focus":["concision","audience"]},
    {"id":"concise-edu-mid-07","level":"mid","profession":"education","title":"Slides that stop narrating themselves","scenario":"Your PD slides are full of meta-commentary: 'In this next section, we're going to take some time to explore some of the ways that we might think about student engagement.' Eleven slides in, you have not said anything yet.","task":"Rewrite the section-opening slide text as one direct claim.","tips":["Cut 'we're going to explore' — just start exploring.","A slide title should be a sentence with content: 'Cold-calling doubles participation.'","Meta-commentary is the sound of a presenter warming up on the audience's time."],"focus":["concision","impact"],"placeholder":"Three engagement moves that work by Friday:"},
    {"id":"concise-edu-mid-08","level":"mid","profession":"education","title":"Three hundred words to three sentences","scenario":"Your email to the counselor about a student runs 300 words: full background, three anecdotes, two theories, and a soft ask at the end. The counselor gets forty emails a day.","task":"Cut it to 3 sentences: the concern, the key evidence, the ask.","tips":["One anecdote — the strongest — carries more than three.","Your theories can wait for the conversation you are requesting.","The ask moves to the front or the top three sentences."],"focus":["concision","structure"]},
    {"id":"concise-edu-mid-09","level":"mid","profession":"education","title":"The redundant-pair sweep","scenario":"The department handbook draft is padded with pairs: 'each and every student,' 'first and foremost,' 'goals and objectives,' 'rules and regulations,' 'help and support.' It reads official and says half as much as it could.","task":"Rewrite one handbook paragraph keeping one word from every pair.","tips":["Pairs feel formal but add zero meaning — pick the stronger word.","'Each student' does everything 'each and every student' does.","Officialese is a costume; clarity is the job."],"focus":["concision","clarity"]},
    {"id":"concise-edu-mid-10","level":"mid","profession":"education","title":"The 100-word abstract","scenario":"The grant portal allows exactly 100 words for your project abstract. Your draft is 218. Every sentence feels necessary because you wrote all of them.","task":"Cut the abstract to 100 words without losing the need, the plan, or the outcome.","tips":["Cut adjectives first, then whole clauses, then whole sentences.","Numbers survive cuts better than descriptions — keep them.","Read the 100-word version fresh: it is almost always better, not just shorter."],"focus":["concision","precision"]},
    {"id":"concise-edu-mid-11","level":"mid","profession":"education","title":"The apology-free request","scenario":"Your request to the principal opens: 'I'm so sorry to bother you with this, and I know how incredibly busy things are right now, and this can absolutely wait if it needs to, but I was wondering if...' The actual request is reasonable and time-sensitive.","task":"Rewrite the request with the throat-clearing removed.","tips":["Preemptive apology teaches the reader your request is skippable.","Busy people prefer direct asks — they cost less to process.","Respect is shown by brevity, not by ceremony."],"focus":["concision","impact"],"placeholder":"Requesting your sign-off on the field trip forms by Friday —"},
    {"id":"concise-edu-mid-12","level":"mid","profession":"education","title":"Permission slip, plain and short","scenario":"The field trip permission slip instructions run a full page: repeated deadlines, three parentheticals, and legal-sounding padding. Families who skim it miss the actual deadline, and the office chases signatures for a week.","task":"Rewrite the instructions in 4 short lines a family can process in ten seconds.","tips":["One line per fact: what, when, cost, deadline.","Put the deadline in its own line — buried deadlines are missed deadlines.","Every extra sentence lowers the chance the important ones get read."],"focus":["concision","audience"]},
    {"id":"concise-edu-mid-13","level":"mid","profession":"education","title":"Minutes that respect the reader","scenario":"Your curriculum committee minutes run two pages of who-said-what. What the absent members need: what was decided, who owns what, and what is due when. The narrative is for nobody.","task":"Rewrite the minutes as decisions, owners, and deadlines — 5 lines maximum.","tips":["Record outcomes, not conversation.","Every line should have a verb in past tense or a name with a date.","If a discussion produced no decision, one line says exactly that."],"focus":["concision","structure"],"placeholder":"Decided: common final adopted for all sections. Owner: —"},
    {"id":"concise-edu-mid-14","level":"mid","profession":"education","title":"Sub plans a stranger can run","scenario":"Your substitute plans run four pages because you explain the reasoning behind every activity. A sub arriving at 7:40 needs to know what to do, in order, with times — not why the warm-up builds retrieval strength.","task":"Cut one period's plan to 6 lines of pure instruction.","tips":["Actions in time order; rationale is for your own planning doc.","Anticipate the two most likely problems in one line each.","A sub skims in the hallway — write for that."],"focus":["concision","audience"]},
    {"id":"concise-edu-mid-15","level":"mid","profession":"education","title":"The recommendation opener, tightened","scenario":"Your recommendation letter opens: 'It is with great pleasure and without any reservation whatsoever that I am writing this letter on behalf of a truly exceptional young person whom I have had the distinct privilege of teaching.' Forty words, zero information.","task":"Rewrite the opening sentence to carry an actual claim about the student.","tips":["The strongest opener is a specific verdict: what she is best at, proven how.","Ceremonial phrases are invisible to readers who see 500 letters.","Spend the first sentence on her, not on your pleasure."],"focus":["concision","impact"],"placeholder":"In fourteen years of teaching chemistry, Priya is the first student who..."},
    {"id":"concise-edu-mid-16","level":"mid","profession":"education","title":"Rubric rows that ramble","scenario":"One row of your project rubric reads: 'The student demonstrates a thorough and comprehensive understanding of the various concepts involved and is able to effectively apply them in a variety of different contexts as appropriate.' Students cannot tell what earns the points.","task":"Rewrite the rubric row so a student knows exactly what to do.","tips":["Replace 'demonstrates understanding' with the observable act.","'Various,' 'effectively,' and 'as appropriate' are unscoreabale — cut them.","Test: could two teachers score the same work the same way from this row?"],"focus":["concision","precision"]},
    {"id":"concise-edu-mid-17","level":"mid","profession":"education","title":"The board deck warm-up, deleted","scenario":"Your budget presentation to the board opens with two slides of thanks, one of background, and one of methodology before the request appears. Board agendas run long, and items get compressed without warning.","task":"Cut the opening so your first spoken sentence contains the request.","tips":["Assume your ten minutes becomes four — front-load accordingly.","Gratitude fits in one clause, not one slide.","If they only hear your first sentence, it should be the ask and the number."],"focus":["concision","impact"]},
    {"id":"concise-edu-mid-18","level":"mid","profession":"education","title":"The IEP summary email","scenario":"Your post-meeting summary to a family runs 400 words recapping everything said. Families reread these emails for months; what they need is what was decided and what happens next, findable in ten seconds.","task":"Cut the summary to 5 sentences: decisions, services, dates, contacts, next review.","tips":["One sentence per category keeps it scannable months later.","Cut who-said-what entirely — the record is the decision, not the dialogue.","Warmth belongs in the first and last sentence, brevity in between."],"focus":["concision","structure"]},
    {"id":"concise-edu-mid-19","level":"mid","profession":"education","title":"Directions students actually read","scenario":"Your assignment directions run 250 words, and students still ask what to do — because they stopped reading at word forty. The over-explanation was meant to prevent questions and instead guarantees them.","task":"Cut the directions to 5 numbered steps of one line each.","tips":["Number the steps; paragraphs hide sequences.","One requirement per line — compound instructions get half-followed.","Long directions signal to students that skimming is required."],"focus":["concision","clarity"],"placeholder":"1. Pick one primary source from the folder."},
    {"id":"concise-edu-mid-20","level":"mid","profession":"education","title":"The pushback paragraph","scenario":"You are pushing back on the new hall-pass policy in an email to the assistant principal. Your draft is 350 words of context, appreciation, concern, more appreciation, and finally a suggestion. The point is one paragraph pretending to be five.","task":"Cut the email to one paragraph: the concern, the evidence, the alternative.","tips":["One round of appreciation is plenty; three reads as anxiety.","The concern stated plainly is more respectful than the concern padded.","End on the alternative — that is what you want acted on."],"focus":["concision","impact"],"placeholder":"I support the goal of the new hall-pass policy, and one part is backfiring:"},
    {"id":"concise-edu-mid-21","level":"mid","profession":"education","title":"The 'I think' epidemic","scenario":"Your data commentary for the department reads: 'I think the scores suggest, and I feel like we're seeing, what seems to me to be a pattern that I believe indicates a gap in fractions.' Everyone knows it is your commentary — the attributions add nothing.","task":"Rewrite the commentary with the qualifiers cut and the claim standing on the data.","tips":["The byline already says you think it — the sentence does not need to.","Keep one 'I think' only where genuine uncertainty needs flagging.","A claim plus its evidence is stronger than a claim plus its apology."],"focus":["concision","precision"],"placeholder":"The scores show a gap in fractions: —"},
    {"id":"concise-edu-mid-22","level":"mid","profession":"education","title":"The welcome-back email","scenario":"Your welcome-back email to the department drafts long: summer recap, philosophy for the year, seventeen logistics items, and inspirational closing. Teachers open it during a frantic setup week.","task":"Cut it to a 5-line email: one warm line, three logistics that matter this week, one line on the year.","tips":["Setup week attention is the scarcest resource of the year — spend it on this week's needs.","Logistics beyond this week go in a doc you link once.","One genuine sentence of warmth beats four paragraphs of it."],"focus":["concision","audience"]},
    {"id":"concise-edu-mid-23","level":"mid","profession":"education","title":"The conference bio, halved","scenario":"You are presenting at a regional teaching conference and the program wants a 50-word bio. Your draft is 130 words covering every role since student teaching. Attendees read bios to decide if your session is worth their slot.","task":"Cut the bio to 50 words that sell the session, not the resume.","tips":["Lead with the credential most relevant to this session's topic.","Years of experience is one number, not a career tour.","Write for the attendee choosing between four concurrent sessions."],"focus":["concision","audience"]},
    {"id":"concise-edu-mid-24","level":"mid","profession":"education","title":"Talking points for the hard call","scenario":"You must call a parent tonight about their son's third missed detention. Your drafted talking points run a page — you over-prepare when nervous, and on the phone that turns into fifteen minutes of circling.","task":"Cut the talking points to 4 lines you can deliver in ninety seconds.","tips":["One line each: the fact, the consequence now in effect, the ask, the support offered.","Over-preparation on paper becomes rambling out loud — trim the script, not just the call.","The shorter your script, the more room to actually listen."],"focus":["concision","clarity"],"placeholder":"1. Dario missed his third detention yesterday — that triggers a Saturday session."},
    {"id":"concise-edu-mid-25","level":"mid","profession":"education","title":"The norms doc that repeats itself","scenario":"Your department norms document says the same three things — start on time, come prepared, disagree respectfully — in nine different sentences across three sections. Length has made it feel official and rendered it unread.","task":"Cut the document to its 3 norms, one line each, plus a one-line intro.","tips":["Each norm once, in its strongest phrasing — delete the echoes.","Three memorable lines outlive three paragraphs.","A norms doc works only if people can recite it."],"focus":["concision","structure"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-edu-mid-01","level":"mid","profession":"education","title":"'Doing much better' isn't a grade","scenario":"You are emailing a parent whose son struggled last quarter. Your draft says he is 'doing much better and really turning things around.' The parent has heard hopeful vagueness before; what she can trust is a number.","task":"Rewrite the update with the specific evidence: grades, missing work, and one observable change.","tips":["'Much better' is a placeholder for numbers you already have — use them.","Quiz average, missing-assignment count, and one dated example beat three adjectives.","Specifics let the parent see the trend herself instead of taking your word."],"focus":["precision","impact"],"placeholder":"Marcus's quiz average is up from 61% to 79% over five weeks, and he has zero missing assignments this quarter."},
    {"id":"precision-edu-mid-02","level":"mid","profession":"education","title":"The data table, distilled","scenario":"Your department's common-assessment spreadsheet shows question-level results across six sections. You plan to project the whole table at the meeting. What the table actually proves: questions 7-9, all on citing evidence, were missed by more than half of students in every section.","task":"Write the one-sentence insight the table supports, with the numbers that matter.","tips":["A table is evidence; the insight is what you conclude from it.","Name the skill and the miss rate — not all thirty cells.","Ask 'what does this prove?' and put only that on the slide."],"focus":["precision","clarity"],"placeholder":"Every section missed the three evidence-citation questions at over 50% — the gap is the skill, not any one class."},
    {"id":"precision-edu-mid-03","level":"mid","profession":"education","title":"'Significant growth' at the board meeting","scenario":"Your slide for the school board says the intervention program produced 'significant growth in student reading outcomes.' A board member who audits budgets for a living will discount that phrase automatically.","task":"Rewrite the claim with the numbers: how many students, how much growth, over what period.","tips":["'Significant' tells a skeptic you might not have looked closely.","Give the count, the measure, and the timeframe in one sentence.","If the honest number is modest, state it plainly — calibrated beats inflated."],"focus":["precision","audience"],"placeholder":"Of the 42 students in the program, 31 gained at least a full grade level in reading in one semester."},
    {"id":"precision-edu-mid-04","level":"mid","profession":"education","title":"The skeptic-proof textbook complaint","scenario":"You want to tell the curriculum director that 'students are really struggling with the new textbook.' A fair skeptic would ask: which students, struggling how, and how do you know it's the book?","task":"Rewrite the claim so it survives all three skeptic questions.","tips":["Anchor it: which unit, which sections, measured how.","Separate what you observed from what you conclude.","Name the comparison — versus last year's text, versus other units."],"focus":["precision","clarity"],"placeholder":"On the two units taught from the new text, quiz averages dropped 12 points across all four sections while everything else held steady."},
    {"id":"precision-edu-mid-05","level":"mid","profession":"education","title":"What, so what, now what","scenario":"You told the principal that ninth-grade absences on Fridays are double the weekday average. You stopped at the fact. She is left to work out what it means and what to do — which is the part you are actually equipped to supply.","task":"Complete the finding in 3 sentences: the fact, its implication, the recommended action.","tips":["What: the number. So what: what it costs students.","Now what: the specific step and who takes it.","A fact without a 'so what' is homework you handed your principal."],"focus":["structure","precision"],"placeholder":"Friday absences in ninth grade run 14% versus 7% on other days. That's a full day of instruction lost per month for about thirty students."},
    {"id":"precision-edu-mid-06","level":"mid","profession":"education","title":"'Soon' is not a date","scenario":"Your curriculum proposal tells administration the pilot materials will be ready 'soon,' teachers will be trained 'shortly after,' and full rollout will happen 'sometime in the spring.' Nobody can plan against any of it.","task":"Rewrite the timeline with dates or date ranges for all three milestones.","tips":["Every 'soon' becomes a date someone can hold you to — that's the point.","If a date is uncertain, give a range and say what pins it down.","Vague timelines read as unplanned, not flexible."],"focus":["precision","structure"],"placeholder":"Pilot materials ready March 3; teacher training the week of March 10; full rollout April 7."},
    {"id":"precision-edu-mid-07","level":"mid","profession":"education","title":"'Engagement was low' won't help her","scenario":"You observed a mentee's lesson and your draft feedback says 'student engagement felt low.' She can't act on a feeling. What you actually saw: during the 12-minute lecture segment, you counted nine students off task and zero hands on the two questions she asked.","task":"Rewrite the feedback as observable, countable evidence she can act on.","tips":["Report what a camera would have caught: counts, minutes, moments.","Tie each observation to a specific segment of the lesson.","Precise evidence feels fairer than vague impressions — and it coaches better."],"focus":["precision","impact"],"placeholder":"During the 12-minute lecture stretch, I counted nine students off task, and both of your questions got zero hands."},
    {"id":"precision-edu-mid-08","level":"mid","profession":"education","title":"'Many parents complained'","scenario":"You are escalating concerns about the new pickup procedure and your draft says 'many parents have complained.' The assistant principal will ask the obvious question: how many, and about what specifically?","task":"Rewrite the escalation with the count, the channels, and the two specific complaints.","tips":["'Many' invites a challenge; 'eleven emails in two weeks' ends one.","Group the complaints into their two or three actual themes.","Keep the raw list available — offering it builds trust in your summary."],"focus":["precision","clarity"],"placeholder":"Eleven families have written since the change — nine about the 20-minute queue, two about the unmarked crossing."},
    {"id":"precision-edu-mid-09","level":"mid","profession":"education","title":"The intervention pitch, benchmarked","scenario":"You want funding for a math intervention block. Your draft says our students 'are behind and need more support.' The principal needs the claim anchored: behind what benchmark, by how much, and how many students.","task":"Write the 2-sentence case with the benchmark, the gap, and the count.","tips":["Behind is a comparison — name the baseline it's measured against.","Count the students in the gap; that number sizes the solution.","One anchored sentence outweighs a paragraph of urgency."],"focus":["precision","impact"],"placeholder":"Fifty-three of our 210 seventh graders are two or more grade levels below benchmark in math, up from 38 last year."},
    {"id":"precision-edu-mid-10","level":"mid","profession":"education","title":"'The pilot went well'","scenario":"The assistant principal asks how the peer-tutoring pilot went, and your instinct is 'really well, the kids loved it.' You have real numbers: 19 of 24 tutees improved their unit grade, and attendance at optional sessions held at 80%.","task":"Give a spoken 2-sentence answer that replaces the adjectives with the evidence.","tips":["Enthusiasm is fine — but lead with the two numbers.","Pick the metric a decision-maker would fund, not the one that flatters.","Name the wrinkle too if there is one; precision includes the misses."],"focus":["precision","concision"]},
    {"id":"precision-edu-mid-11","level":"mid","profession":"education","title":"The mentee's vague worry, sharpened","scenario":"Your mentee says 'my third period just isn't getting it.' Before you can coach her, the problem needs edges. You sit down with her gradebook to turn the feeling into a finding.","task":"Write the precise version of her problem statement, as you'd model it for her.","tips":["Which students, which skill, on what evidence — make her name all three.","'Isn't getting it' might be five students and one concept; find out.","A problem with numbers attached is already half-diagnosed."],"focus":["precision","clarity"],"placeholder":"Eight of my 26 third-period students scored below 60% on both fraction quizzes — the rest are at or above 75%."},
    {"id":"precision-edu-mid-12","level":"mid","profession":"education","title":"The enrollment estimate, honestly ranged","scenario":"The principal asks how many students will sign up for your new elective so she can decide on sections. You genuinely don't know exactly, but you have course-fair interest cards and past patterns. 'A lot of interest' helps nobody.","task":"Write a reply that gives a range, the basis for it, and what would firm it up.","tips":["A ranged estimate with a basis beats fake certainty and vague hope.","Say what the range rests on: 61 interest cards, historical conversion around 60%.","Name the date when you'll know more — that's part of the answer."],"focus":["precision","structure"],"placeholder":"My estimate is 35-45 students: 61 interest cards, and about 60% of cards historically convert to enrollment."},
    {"id":"precision-edu-mid-13","level":"mid","profession":"education","title":"'A lot of missing work'","scenario":"You are referring a student to the intervention team and your draft says he has 'a lot of missing work lately and seems checked out.' The team ranks cases by specifics, and yours has none.","task":"Rewrite the referral line with counts, dates, and the observable change.","tips":["Count it: how many assignments, over which weeks, versus his baseline.","'Checked out' becomes what you saw — head down, no materials, since when.","The team can only triage what you quantify."],"focus":["precision","audience"],"placeholder":"Jaylen has missed 7 of 9 assignments since March 1 — he'd missed 2 all semester before that — and has come without materials daily for two weeks."},
    {"id":"precision-edu-mid-14","level":"mid","profession":"education","title":"The budget line, per student","scenario":"You are defending a $2,400 request for classroom novel sets. As a lump sum it invites scrutiny; as a per-student figure with a lifespan, it almost defends itself. You know the math: 120 students a year, books last five years.","task":"Write the one-sentence justification that does the arithmetic for the reader.","tips":["Break the big number into the unit the reader cares about: cost per student per year.","Do the division yourself — never make an approver do math to agree with you.","Pair the unit cost with what it replaces or prevents."],"focus":["precision","impact"],"placeholder":"That's $2,400 for sets that serve 120 students a year for five years — four dollars per student per year."},
    {"id":"precision-edu-mid-15","level":"mid","profession":"education","title":"'Reading levels are down'","scenario":"At a grade-team meeting you hear yourself say 'reading levels are down this year.' A colleague asks what you mean, and you realize the claim has no edges: which grades, which measure, down from what?","task":"Restate the claim precisely: grades, measure, size of the change, and comparison point.","tips":["Name the assessment and the window — 'down' needs a baseline.","Give the size: a decline of 4 percentile points is different from 14.","If only one grade band drives it, say so; averages hide the story."],"focus":["precision","clarity"],"placeholder":"On the fall benchmark, grade 7 reading dropped from the 52nd to the 44th percentile; grades 6 and 8 held flat."},
    {"id":"precision-edu-mid-16","level":"mid","profession":"education","title":"The causal claim you can't quite make","scenario":"Scores rose the same year you launched the writing program, and your draft report says the program 'transformed our results.' Honest version: scores rose 9 points, the program is one plausible driver, and the schedule change happened the same year.","task":"Rewrite the claim at the strength the evidence actually supports.","tips":["Say what rose and by how much — that part is solid.","Attribute with calibrated language: 'coincided with,' 'likely contributed.'","Overclaiming once costs you the benefit of the doubt forever."],"focus":["precision","impact"],"placeholder":"Writing scores rose 9 points in the program's first year — the program is the most likely driver, though the new schedule changed the same fall."},
    {"id":"precision-edu-mid-17","level":"mid","profession":"education","title":"The anecdote that needs a number","scenario":"For the board presentation on the mentorship program, you have a genuinely moving story about one student. Alone, it's an anecdote a skeptic dismisses. Paired with the participation and grade data, it becomes the face of a pattern.","task":"Write the 2-sentence pairing: the number that shows the pattern, then the story that makes it real.","tips":["The number proves it's a pattern; the story proves it matters.","One student, named specifically (or anonymized), beats 'students like these.'","Order matters for skeptics: pattern first, face second."],"focus":["precision","audience"],"placeholder":"Of 30 mentored students, 24 raised their GPA by half a point or more. One of them is Dana, who started the year failing three classes."},
    {"id":"precision-edu-mid-18","level":"mid","profession":"education","title":"'Most teachers are on board'","scenario":"You are telling the principal the department supports moving to standards-based grading. Your draft says 'most teachers are on board.' You ran an actual straw poll: 8 support it, 2 are opposed, 2 want more time.","task":"Rewrite the sentence with the real distribution, including the opposition.","tips":["Report the split — hiding the two opponents will surface later and cost you.","'Most' rounds up; 8-2-2 is a claim you can stand behind in any room.","Naming the concerns of the two opposed makes the eight more credible."],"focus":["precision","clarity"],"placeholder":"The department polled 8 in favor, 2 opposed, 2 undecided — the opposition centers on report-card mechanics, not the model."},
    {"id":"precision-edu-mid-19","level":"mid","profession":"education","title":"'End of week' means Friday when?","scenario":"Your department email asks everyone to submit exam drafts 'by end of week.' Last time you wrote that, submissions arrived from Thursday afternoon to Sunday night, and you spent the weekend chasing them.","task":"Rewrite the deadline sentence so it cannot be read two ways.","tips":["Day, date, and time — deadlines are coordinates, not vibes.","Say what happens at that time: 'I assemble the exam Friday at 4.'","Where the file goes is part of the deadline; name the folder."],"focus":["precision","concision"],"placeholder":"Please upload your exam draft to the shared folder by Friday, March 21, at 3:00 pm — I assemble the full exam at 4:00."},
    {"id":"precision-edu-mid-20","level":"mid","profession":"education","title":"The referral data's real story","scenario":"You pulled a semester of behavior referrals for the leadership team. The raw count says referrals are up 20%. The pattern underneath: nearly all of the increase happens in the four minutes between classes, in two hallways.","task":"Write the one-sentence finding that names the pattern, not just the total.","tips":["The total alarms; the pattern directs — lead with where and when.","Two hallways and a four-minute window is a solvable problem; '20% up' is a mood.","Keep the denominator honest: up 20% from what base?"],"focus":["precision","impact"],"placeholder":"Referrals are up 20%, but 80% of the increase happens during passing periods in the B and C hallways."},
    {"id":"precision-edu-mid-21","level":"mid","profession":"education","title":"'My classes are too big'","scenario":"You want to raise class size with the principal before next year's schedule locks. 'My classes are too big' is an opinion. The facts: three of your five sections are at 34, the contract cap is 32, and lab stations seat 30.","task":"Write the 2-sentence version built on the checkable facts.","tips":["Anchor to the two hard limits: the contract cap and the physical room.","Name the sections and the counts — specifics move schedules, feelings don't.","End with the specific relief you're asking for."],"focus":["precision","structure"],"placeholder":"Three of my five sections are at 34 students, above the contract cap of 32 — and my lab seats 30."},
    {"id":"precision-edu-mid-22","level":"mid","profession":"education","title":"'Studies show' — which study?","scenario":"Your PD slide says 'studies show retrieval practice dramatically improves retention.' A skeptical veteran in the second row is exactly the person 'studies show' fails to convince. You actually know the research.","task":"Rewrite the claim with a named source and a concrete effect a teacher can picture.","tips":["One named, checkable source beats an anonymous chorus of 'studies.'","Translate the effect size into classroom terms: what a class of 30 would look like.","Invite the skeptic to check — confidence in your source is persuasive."],"focus":["precision","audience"],"placeholder":"In Roediger and Karpicke's 2006 study, students who practiced retrieval remembered about 50% more a week later than students who reread."},
    {"id":"precision-edu-mid-23","level":"mid","profession":"education","title":"The percentage that flatters","scenario":"Your after-school program report could say 'attendance doubled.' The honest numbers: it went from 6 students to 12, in a school of 400. Both framings are true; only one survives a board member doing the math.","task":"Write the sentence that reports the result honestly with both the percentage and the counts.","tips":["Small denominators make percentages shout — give the counts alongside.","State the base: 12 of roughly 400 eligible students.","Framing you'd defend under questioning is the only framing worth using."],"focus":["precision","clarity"],"placeholder":"Attendance doubled from 6 to 12 students this quarter — still a small share of the 400 eligible, so the next test is whether growth continues."},
    {"id":"precision-edu-mid-24","level":"mid","profession":"education","title":"'Chronically absent,' defined","scenario":"In your intervention meeting notes you called a student 'chronically absent.' The district defines chronic absence as missing 10% or more of enrolled days. If your notes go into her file, the term needs to match the definition — and the count.","task":"Rewrite the note using the defined term correctly, with the student's actual numbers.","tips":["Terms of art have thresholds — use the number that triggers the label.","State days missed over days enrolled so anyone can verify.","In records that follow a student, precision is protection."],"focus":["precision","clarity"],"placeholder":"Amara has missed 14 of 92 enrolled days (15%), which meets the district's chronic-absence threshold of 10%."},
    {"id":"precision-edu-mid-25","level":"mid","profession":"education","title":"One number to rule the update","scenario":"You have thirty minutes of data from the tutoring pilot and ninety seconds of the principal's attention at the leadership meeting. You must choose the single number that best tells the story — and say it in a sentence.","task":"Deliver the spoken one-sentence update built around your chosen number, plus one sentence of context.","tips":["Pick the number closest to the decision she has to make.","One number, said clearly, is remembered; five numbers become noise.","Have the rest of the data ready for questions — that's where it belongs."],"focus":["precision","concision"]}
  ],
  "executive-presence": [
    {"id":"presence-edu-mid-01","level":"mid","profession":"education","title":"Options memo, minus the shrug","scenario":"The principal asked your committee to evaluate three schedule models. Your draft memo lays out all three neutrally and ends with 'happy to discuss whichever direction you prefer.' She asked your committee precisely so someone would take a position.","task":"Rewrite the ending as an owned recommendation with your top reason.","tips":["Presenting options without a pick outsources your judgment — the one thing she asked for.","Name your recommendation, your strongest reason, and the main tradeoff you accept.","'We recommend' is a phrase that builds careers; 'whichever you prefer' isn't."],"focus":["impact","clarity"],"placeholder":"We recommend Model B. It protects daily intervention time, and we accept the tradeoff of shorter passing periods."},
    {"id":"presence-edu-mid-02","level":"mid","profession":"education","title":"The hedge harvest","scenario":"Your draft comment for the staff meeting reads: 'I sort of think maybe we could possibly look at perhaps changing how we kind of handle late work?' Four hedges deep, the actual position — you think the policy should change — has disappeared.","task":"Rewrite the statement with at most one calibrated qualifier.","tips":["Count your hedges, keep the one that carries real uncertainty, cut the rest.","'I think we should change the late-work policy' is still polite — and audible.","Hedging every clause reads as asking permission to have an opinion."],"focus":["clarity","impact"],"placeholder":"I think we should change the late-work policy, and I'd start with the 50%-floor rule."},
    {"id":"presence-edu-mid-03","level":"mid","profession":"education","title":"Three reasons, announced","scenario":"You have fifteen minutes with the principal to make the case for a dedicated literacy block. Your argument has three good reasons, but in rehearsal they blur into one long stream she'd have to untangle herself.","task":"Write your opening two sentences: the position, then the signpost for the three reasons.","tips":["Announce the map: 'three reasons — schedule, staffing, and results.'","Signposting isn't padding; it's how a listener holds your logic.","Number them out loud as you go: first, second, third."],"focus":["structure","clarity"],"placeholder":"I'm asking for a daily 40-minute literacy block, for three reasons: the data, the staffing we already have, and what our feeder schools are seeing."},
    {"id":"presence-edu-mid-04","level":"mid","profession":"education","title":"Fact, then judgment, labeled","scenario":"In an observation debrief, your notes mix what happened with what you concluded: 'the lesson lost the kids because the pacing was off.' The teacher can dispute a judgment; she can't dispute a fact — and she deserves to know which is which.","task":"Rewrite the feedback as one labeled fact and one labeled judgment.","tips":["'What I saw' and 'what I make of it' are different sentences — keep them apart.","Facts: times, counts, quotes. Judgments: your read, owned as yours.","Separating them makes your judgment more trusted, not less."],"focus":["clarity","precision"],"placeholder":"Here's what I saw: the warm-up ran 18 minutes of a 50-minute period. My read is that it cost you the practice time the objective needed."},
    {"id":"presence-edu-mid-05","level":"mid","profession":"education","title":"Pushing back without apologizing","scenario":"The principal wants the new grading policy rolled out in three weeks. You believe mid-semester is the wrong time and January is right. Your drafted objection opens with 'I'm so sorry to push back on this, and I could be totally wrong, but...'","task":"Rewrite the pushback: respectful, unapologetic, with your reason and alternative.","tips":["Disagreement offered professionally needs no apology — it's your job.","State the concern, the evidence, and your alternative in three sentences.","'I recommend we wait until January, and here's why' is respect, not defiance."],"focus":["impact","structure"],"placeholder":"I recommend we launch in January instead. Changing grade calculations mid-semester creates disputes we can't win, and a semester boundary gives us a clean start."},
    {"id":"presence-edu-mid-06","level":"mid","profession":"education","title":"Owning the room in sentence one","scenario":"You are opening a PD session for forty colleagues, some of whom taught for a decade before you arrived. Your drafted opener apologizes: 'I know you're all tired, and I'm sure a lot of you know more about this than I do...'","task":"Write an opening line that earns attention instead of forgiveness.","tips":["Never open by arguing against your own session.","Lead with the concrete value: what they'll walk out able to do.","Respect the veterans by being useful, not by being small."],"focus":["impact","audience"],"placeholder":"In the next hour you'll get three feedback techniques you can use fourth period today — and we'll practice each one."},
    {"id":"presence-edu-mid-07","level":"mid","profession":"education","title":"'I'll try' versus 'I will'","scenario":"The assistant principal asks if your department can have the new course proposals ready for the February board packet. Your instinct is 'we'll try our best.' The truth: you can, if the January PD day stays protected for the work.","task":"Rewrite the answer as a commitment with its real condition.","tips":["'I'll try' hedges even when you're confident — say what you'll actually do.","A commitment with a named condition is stronger than vague willingness.","If the condition fails, you've already flagged it — that's cover you earned."],"focus":["clarity","precision"],"placeholder":"Yes — we'll have them ready for the February packet, as long as the January 12 PD day stays protected for the writing time."},
    {"id":"presence-edu-mid-08","level":"mid","profession":"education","title":"Mixed results, steady voice","scenario":"You are presenting the tutoring pilot to the school board: math scores improved meaningfully, reading didn't move. The temptation is to spin or to over-apologize. Presence is reporting both with the same steady voice.","task":"Write the 3-sentence summary that owns both results and states what happens next.","tips":["Give the win and the miss the same sentence structure — no burying.","Calibrated confidence: sure about what happened, honest about what you don't know yet.","End with your recommendation; mixed results still deserve a decision."],"focus":["impact","precision"],"placeholder":"Math scores rose 11 points for tutored students; reading scores didn't move. We know why the math model worked, and we're changing the reading approach rather than scaling it."},
    {"id":"presence-edu-mid-09","level":"mid","profession":"education","title":"The email that asks permission to exist","scenario":"Your email to the district curriculum office reads: 'Sorry to bother you! I just wanted to quickly check if maybe there's any chance the pacing guide could possibly be revisited at some point?' You chair the department; you're allowed to make requests.","task":"Rewrite the email in two sentences that make the request like a peer.","tips":["Cut 'just,' 'quickly,' 'maybe,' and both apologies — then see what's left.","Name the request and the reason; that's the whole email.","Politeness lives in tone, not in shrinking."],"focus":["concision","impact"],"placeholder":"I'd like to propose two revisions to the grade 8 pacing guide before next year's printing. Could we get 20 minutes in the next two weeks?"},
    {"id":"presence-edu-mid-10","level":"mid","profession":"education","title":"Owning the unpopular decision","scenario":"Your department must adopt the district's common rubric, and you agreed in the chairs' meeting that it's the right call. At your department meeting, the easy move is 'sorry, the district is making us do this.' That buys sympathy and spends your authority.","task":"Write the 2-3 sentence announcement in which you own the decision you actually support.","tips":["If you agreed with the call, say so — blaming 'them' teaches your team you're powerless.","Give your real reason for supporting it, not just the mandate.","You can own a decision and still acknowledge the cost of the change."],"focus":["impact","clarity"],"placeholder":"We're adopting the district rubric next semester, and I support the move — our students transfer between schools too often for four different definitions of proficient."},
    {"id":"presence-edu-mid-11","level":"mid","profession":"education","title":"The structured 'it depends'","scenario":"A board member asks whether smaller class sizes would raise scores. The honest answer depends on grade level and subject. 'It depends' alone sounds evasive; a structured version of it sounds like expertise.","task":"Give a spoken answer that says 'it depends,' then names the two things it depends on with your read of each.","tips":["'It depends — on two things' turns a dodge into a framework.","Give your actual leaning at the end; structure without a position is still evasion.","Two branches is presence; five is a lecture."],"focus":["structure","audience"]},
    {"id":"presence-edu-mid-12","level":"mid","profession":"education","title":"'Just wanted to touch base'","scenario":"Your message to the principal opens 'Just wanted to touch base and circle back about the thing we discussed.' Three soft phrases, zero information. You want her decision on the co-teaching proposal by Friday.","task":"Rewrite the message with a direct verb and the actual deadline.","tips":["'Touch base' and 'circle back' are verbs that do nothing — name the real action.","Ask for the decision, the date, and nothing else.","Directness with a reason reads as competence, not pressure."],"focus":["concision","clarity"],"placeholder":"Could you confirm a decision on the co-teaching proposal by Friday? Master scheduling starts Monday and the answer changes two teachers' assignments."},
    {"id":"presence-edu-mid-13","level":"mid","profession":"education","title":"Disagreeing with the veteran","scenario":"In the curriculum meeting, the most senior teacher in the department dismisses the writing-portfolio proposal you've spent a month building: 'we tried that in 2011 and it was a disaster.' The room looks at you.","task":"Write your spoken response: respectful of the history, firm on the proposal.","tips":["Take the objection seriously by naming what's different now — specifically.","Don't relitigate 2011; distinguish it.","Steady beats sharp: acknowledge, differentiate, restate your position."],"focus":["impact","structure"],"placeholder":"That history matters — and two things are different this time: the portfolios are digital, and we're piloting with two sections, not the whole grade."},
    {"id":"presence-edu-mid-14","level":"mid","profession":"education","title":"From options list to recommendation","scenario":"Your email to the principal about the master-schedule conflict lists four ways to resolve it, each with pros and cons, and asks 'what would you like to do?' You know option two is right; you've known since Tuesday.","task":"Rewrite the email to lead with your recommendation, keeping the alternatives as one line.","tips":["Lead with the pick; the alternatives become 'we also considered' — one sentence.","Say what you'd do if it were your call, because functionally she's asking that.","You can be corrected; you can't be respected for hiding."],"focus":["structure","impact"],"placeholder":"I recommend option two: move AP Chem to period 1 and swap the lab blocks. It resolves all three conflicts and touches only two teachers' schedules."},
    {"id":"presence-edu-mid-15","level":"mid","profession":"education","title":"The agenda, out loud","scenario":"You are opening a parent conference that has three items: the grade, the behavior pattern, and the support plan. Without a spoken map, these meetings sprawl and end mid-argument when time runs out.","task":"Write your opening 2 sentences: warm, then the signposted agenda with the time frame.","tips":["Naming the agenda out loud is leadership, not stiffness — parents relax when they can see the shape.","Put the plan last so the meeting ends on the path forward.","'We have 30 minutes' is a kindness, not a threat."],"focus":["structure","audience"],"placeholder":"Thanks for coming in — we have 30 minutes, and I'd like to cover three things: where Eli's grade stands, a pattern I'm seeing in class, and the plan I want to build with you."},
    {"id":"presence-edu-mid-16","level":"mid","profession":"education","title":"Confidence, calibrated out loud","scenario":"The principal asks whether the new intervention schedule will fix the eighth-grade math gap. You believe it will help substantially, but you wouldn't bet the year on it. Both false certainty and mush are available; presence is the third option.","task":"Write a 2-sentence answer that states your confidence level and what would update it.","tips":["Say how sure you are in plain terms: 'I'd put it at likely, not certain.'","Name the checkpoint where you'll know more — that makes the uncertainty responsible.","Calibrated language is what lets people trust your certain moments."],"focus":["precision","clarity"],"placeholder":"I'm confident it closes part of the gap — I'd say likely, not certain. The November benchmark will tell us if the effect is big enough."},
    {"id":"presence-edu-mid-17","level":"mid","profession":"education","title":"The mistake, owned in active voice","scenario":"You built the exam schedule and put two exams in the same room at the same time; it wasn't caught until students showed up. Your draft note to staff says 'an error occurred in the scheduling process.' The process didn't make the error. You did.","task":"Rewrite the note in active voice: what you got wrong, the fix, and the prevention.","tips":["'I scheduled two exams into room 118' — the sentence hurts once and earns trust for years.","Fix first, prevention second, self-flagellation never.","Passive voice in an apology reads as exactly what it is."],"focus":["clarity","impact"],"placeholder":"I made a scheduling error: I booked two exams into room 118 for the same block. Here's the fix for Thursday, and the double-check I've added so it can't recur."},
    {"id":"presence-edu-mid-18","level":"mid","profession":"education","title":"First meeting as chair","scenario":"You've just been named department chair over colleagues who have taught longer than you. Your first meeting opener will set the tone for two years. Overclaiming authority will backfire; apologizing for having it will too.","task":"Write your 3-sentence opening: how you'll run things, what you're asking of them, what they can expect from you.","tips":["Skip the humility theater and the manifesto both — be concrete about how decisions get made.","One specific commitment ('agendas 48 hours ahead') beats five values.","Acknowledge their experience by using it: name what you'll rely on them for."],"focus":["impact","audience"],"placeholder":"Here's how I intend to run this department: decisions made in this room, agendas 48 hours ahead, and your expertise driving the curriculum calls."},
    {"id":"presence-edu-mid-19","level":"mid","profession":"education","title":"The incident report that hides its author","scenario":"Your incident report reads: 'It was decided that the student would be moved, and a call home was made.' Decided by whom? Made by whom? In a report that may be reviewed later, agentless sentences read as evasion even when nothing is wrong.","task":"Rewrite the two sentences in active voice with named actors.","tips":["Every action in a formal report needs an actor: who decided, who called.","Active voice is accountability in grammar form.","If you'd stand behind the decision, put your name in the sentence."],"focus":["clarity","precision"],"placeholder":"I moved Devon to the front table for the rest of the period, and I called his mother at 2:40 to describe what happened."},
    {"id":"presence-edu-mid-20","level":"mid","profession":"education","title":"Credibility without the resume","scenario":"At a community meeting about the new reading curriculum, a parent asks pointedly why they should trust your judgment on this. Reciting your degrees would sound defensive. Your actual credibility is in the work: the results, the process, the care.","task":"Write your spoken 2-3 sentence answer that establishes credibility through the work, not the titles.","tips":["Point to evidence of process: what you examined, whom you consulted, what you piloted.","One concrete result carries more weight than any credential.","Answer calmly as if the question were fair — because it is."],"focus":["audience","impact"]},
    {"id":"presence-edu-mid-21","level":"mid","profession":"education","title":"Holding the line in a loud room","scenario":"At the staff meeting, your proposal to standardize homework loads meets vocal resistance from three colleagues at once. Your instinct is to soften it live: 'well, it's just an idea, we don't have to...' — abandoning a position the data supports.","task":"Write the spoken response that holds the position while genuinely taking the objections.","tips":["Restate the position once, calmly — retreating under volume teaches the room how to beat you.","Name the objections as fair and answerable, then answer the strongest one.","Offer a path: pilot it, review in eight weeks, adjust on evidence."],"focus":["impact","structure"],"placeholder":"I hear three real concerns, and I want to answer the biggest one — but I'm not walking back the proposal, because the survey data is clear."},
    {"id":"presence-edu-mid-22","level":"mid","profession":"education","title":"One screen for the superintendent","scenario":"The superintendent's office asked for your view on expanding the dual-enrollment program. This is your one email to the most senior reader you'll write to this year. It must be one screen, decided in tone, and impossible to misread.","task":"Write the 4-sentence email: position, top two reasons, the one risk, the ask.","tips":["Senior readers reward compression: position in sentence one.","Two reasons and one honestly-named risk read as judgment, not salesmanship.","End with exactly what you're asking them to do."],"focus":["concision","impact"],"placeholder":"I support expanding dual enrollment to 11th grade, for two reasons. First, our completion data:"},
    {"id":"presence-edu-mid-23","level":"mid","profession":"education","title":"The apology audit","scenario":"Your draft email rescheduling the department meeting contains four apologies: sorry for the change, sorry for the short notice, sorry for any inconvenience, sorry again. One of them is warranted. Four make you sound like the problem.","task":"Rewrite the email keeping exactly one apology, placed where it counts.","tips":["Apologize once, specifically, for the real cost — the short notice.","Replace the other three with information: new time, reason, what to bring.","Chronic apology erodes the authority your role needs."],"focus":["concision","impact"],"placeholder":"I'm moving Tuesday's meeting to Thursday at 3:15 — apologies for the short notice. Same agenda; bring your exam drafts."},
    {"id":"presence-edu-mid-24","level":"mid","profession":"education","title":"'Here's the fact, here's my read'","scenario":"The principal asks why a strong teacher's AP results dipped this year. You have the fact (scores fell from 78% to 64% passing) and a judgment (the new textbook sequence left less review time). Presence is giving both — labeled.","task":"Write the spoken 2-sentence answer that separates the fact from your read.","tips":["Lead with the verifiable fact, unspun.","Then 'my read is' — owned, falsifiable, open to challenge.","Blending them makes both less trustworthy; separating them makes you more."],"focus":["precision","clarity"],"placeholder":"The fact: pass rates fell from 78% to 64%. My read is the new textbook sequence squeezed out three weeks of review — and there's a way to test that."},
    {"id":"presence-edu-mid-25","level":"mid","profession":"education","title":"The close that asks for the decision","scenario":"You've just spent ten minutes presenting the literacy-block proposal to the leadership team, and your drafted ending is 'so... yeah, that's the proposal. Any thoughts?' Ten minutes of work dissolving into a shrug.","task":"Write the closing 2 sentences: the recap in one line, then the specific decision you're requesting and when.","tips":["End with the ask, not an invitation to wander.","Name the decision, the deadline, and why the deadline is real.","'Any thoughts?' is how strong proposals die politely."],"focus":["impact","structure"],"placeholder":"That's the case: one block, existing staff, measurable by November. I'm asking for a yes or no by Friday so it makes the master schedule."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-edu-mid-01","level":"mid","profession":"education","title":"'Why did my kid get a B+?'","scenario":"A parent opens the conference with a hard edge: 'Explain to me exactly why my daughter got a B+ when she's never gotten below an A.' Your instinct is to walk through the whole grading system first. The direct answer exists: two quiz scores and a late project.","task":"Write your spoken first response: the direct answer, then the offer to go deeper.","tips":["Answer the actual question in sentence one — the specific items that made the grade.","The gradebook walkthrough is support, offered second, not a shield raised first.","Directness lowers the temperature; deflection raises it."],"focus":["clarity","audience"],"placeholder":"The B+ comes from three specific items: two quiz scores in the low 80s and the research project, which came in a week late."},
    {"id":"pressure-edu-mid-02","level":"mid","profession":"education","title":"The board member's curveball","scenario":"You are presenting the reading program when a board member cuts in: 'We've increased spending three years running and scores are flat. Why should we keep paying for this?' The room goes quiet. You have a real answer — spending went to closing a widening gap that would otherwise show as decline.","task":"Write your spoken answer: direct response first, then the one piece of evidence.","tips":["Take the question head-on — 'here's why' — before any context.","One strong piece of evidence beats a defensive data tour.","Respect the question's premise where it's right: scores are flat. Explain what that hides."],"focus":["impact","precision"],"placeholder":"Because flat is the success in this case: our incoming cohorts arrived further behind each year, and holding scores flat meant closing a growing gap."},
    {"id":"pressure-edu-mid-03","level":"mid","profession":"education","title":"'I don't know' that builds trust","scenario":"The principal asks, in front of the leadership team, what percentage of your department's students passed the state test with distinction. You know the pass rate cold; the distinction breakdown you've never pulled. Guessing is available, and fatal.","task":"Write the spoken response: the honest 'I don't know,' what you do know, and when you'll have the answer.","tips":["Say the part you know, name the part you don't, and give the delivery time.","A wrong guess is remembered forever; a crisp 'by tomorrow at noon' is respected.","Don't over-apologize for not knowing — just close the gap fast."],"focus":["clarity","precision"],"placeholder":"I don't have the distinction breakdown in front of me — the overall pass rate is 84%, and I'll have the full split to you by noon tomorrow."},
    {"id":"pressure-edu-mid-04","level":"mid","profession":"education","title":"'You have it out for my son'","scenario":"Mid-conference, a parent says flatly: 'I think you have it out for my son.' Every defensive route — outrage, a list of your kindnesses, retreating — makes it worse. What holds: acknowledging the concern, returning to the documented record, and keeping the focus on the student.","task":"Write your spoken response to the accusation.","tips":["Don't argue about your character; point to the record — dates, work, communications.","Acknowledge the feeling without accepting the claim: 'I hear that this feels personal.'","Steer to the shared goal in the same breath: what helps him from here."],"focus":["audience","impact"],"placeholder":"I hear that this feels personal, and I want to show you it isn't — let's look at the actual work and dates together, because we both want the same thing for him."},
    {"id":"pressure-edu-mid-05","level":"mid","profession":"education","title":"The loaded question","scenario":"At the family curriculum night, a parent asks: 'Don't you think this new math program is failing our kids?' The question assumes its own answer. Agreeing is false; a flat 'no' sounds defensive; the honest answer has a real concern inside it worth naming.","task":"Write a spoken answer that rejects the framing while honoring the legitimate worry.","tips":["Separate the loaded frame from the fair question inside it, and answer the fair one.","Concede what's true — the transition has been bumpy — without accepting 'failing.'","Give the evidence you'd want as that parent."],"focus":["audience","clarity"],"placeholder":"'Failing' isn't what the data shows — but the transition has been genuinely bumpy, and I want to speak to that directly."},
    {"id":"pressure-edu-mid-06","level":"mid","profession":"education","title":"The two-part question","scenario":"The assistant principal asks: 'Is the common exam ready, and are you confident the new teachers can grade it consistently?' Under pressure you'll answer the comfortable half and drift. Both halves deserve answers — in order, labeled.","task":"Write the spoken answer that takes both parts explicitly.","tips":["Number them back: 'On the first — yes. On the second — mostly, and here's the gap.'","Answering both halves crisply is rarer than it should be; it reads as command.","If one half needs a longer answer, say so and give the headline now."],"focus":["structure","clarity"],"placeholder":"Two answers. The exam: ready, printed Friday. Grading consistency: mostly — the two new teachers and I are calibrating on sample essays Wednesday."},
    {"id":"pressure-edu-mid-07","level":"mid","profession":"education","title":"Interrupted at slide three","scenario":"Four minutes into your staffing presentation, the principal interrupts: 'Skip ahead — just tell me what you need.' Your remaining nine slides are now a liability. The answer she wants exists: one additional section of English 9 and a 0.4 staffing increase.","task":"Write the spoken response that lands the ask in two sentences and lets the deck go.","tips":["Never defend the deck — give the answer the interruption asked for.","The ask, the cost, and the deadline: that's the whole response.","Offer the detail as follow-up: 'the backup for that is in the deck I'll leave with you.'"],"focus":["concision","impact"],"placeholder":"One additional section of English 9, which is a 0.4 staffing increase — and I need the decision by March 15 to make the master schedule."},
    {"id":"pressure-edu-mid-08","level":"mid","profession":"education","title":"The question you prepped wrong","scenario":"You prepared for the PTA meeting expecting questions about the phone policy's rules. The first question is about something you didn't prep: what evidence supported adopting it? You have partial knowledge — the two studies the committee read — but not the full citation trail.","task":"Write the spoken answer that gives what you know cleanly and names the limit honestly.","tips":["Deliver your partial knowledge with confidence — partial and honest beats complete and invented.","Draw the line clearly: 'what I can't cite tonight is X, and I'll post it.'","Composure under a surprise question is the credibility test — pace yourself."],"focus":["clarity","precision"],"placeholder":"The committee based it on two things I can speak to tonight — the attention research and pilot data from two district schools — and I'll post the full citations by Friday."},
    {"id":"pressure-edu-mid-09","level":"mid","profession":"education","title":"'How long until it's fixed?'","scenario":"After a gradebook sync error garbled two weeks of entries, the principal asks how long until every grade is verified. The honest answer is uncertain: three days if the export works, a week if you rebuild by hand. She needs a commitment she can relay to families.","task":"Write the answer that commits under uncertainty without gambling.","tips":["Give the range with the fork named: 'three days if X, seven if not.'","Commit to a checkpoint you fully control: 'I'll know which path by tomorrow at 10.'","A structured range is a real answer; 'as soon as possible' is not."],"focus":["precision","structure"],"placeholder":"Three days if tonight's export is clean, seven if I rebuild by hand — and I'll know which one by 10 tomorrow morning."},
    {"id":"pressure-edu-mid-10","level":"mid","profession":"education","title":"The union rep's challenge","scenario":"At the staff meeting, the building rep challenges your PLC proposal: 'This is contractually protected prep time, and you're asking people to give it up.' He's half right — the proposal does use one prep block, voluntarily, with a duty waived in trade.","task":"Write the spoken response that concedes the true half and corrects the record on the rest.","tips":["Concede first what's accurate — it's the fastest way to earn the correction.","Then the precise correction: voluntary, one block, duty waived in exchange.","Stay on facts and the contract language; matching his heat loses the room."],"focus":["precision","impact"],"placeholder":"You're right that it uses a prep block — and three things matter: it's voluntary, it's one block, and participants are released from morning duty in trade."},
    {"id":"pressure-edu-mid-11","level":"mid","profession":"education","title":"The yes-or-no that deserves both","scenario":"The principal asks point-blank: 'Will your department make the textbook adoption deadline, yes or no?' The truthful answer is yes — with one dependency on the vendor's sample delivery that she should know about.","task":"Write the answer: the yes first, the one dependency second, nothing else.","tips":["Give the yes in the first word — burying it under the caveat reads as a no.","One dependency, one sentence, with what you're doing to manage it.","Resist narrating the whole project; she asked a binary question."],"focus":["clarity","concision"],"placeholder":"Yes — with one dependency: the vendor samples are due March 1, and I'm confirming shipment this week."},
    {"id":"pressure-edu-mid-12","level":"mid","profession":"education","title":"The statistic from the internet","scenario":"A parent at the curriculum meeting cites a statistic from a website: 'Schools that use this program score 30% worse. Why are we using it?' You've never seen the number, and you suspect it's from a different program or a misread. You can't verify it live.","task":"Write the spoken response that handles an unverifiable claim without dismissing the parent.","tips":["Don't accept or mock the number — take it seriously enough to check it: 'send me the source.'","Restate what you can verify tonight: your own school's data.","Commit to a public follow-up; that converts a gotcha into a process."],"focus":["audience","precision"],"placeholder":"I haven't seen that figure and I'd genuinely like the source — send it to me tonight. Here's what I can verify: our own students' results over two years."},
    {"id":"pressure-edu-mid-13","level":"mid","profession":"education","title":"Feedback about your feedback","scenario":"Your mentee, voice shaking slightly, tells you your observation notes feel like 'a list of everything wrong' and that she leaves your debriefs discouraged. Your first internal response is defensive — you spent hours on those notes. That response is the wrong one.","task":"Write your spoken reply: non-defensive, taking the feedback seriously, with one concrete change.","tips":["Thank her plainly — it cost her something to say it, and she's your customer here.","Don't defend your intent; address her experience.","Name one specific change you'll make starting next debrief."],"focus":["audience","impact"],"placeholder":"I'm glad you told me — that's not the effect I want, and it's mine to fix. Starting next time: one priority, one strength, and we build the plan together."},
    {"id":"pressure-edu-mid-14","level":"mid","profession":"education","title":"'What's your biggest problem?'","scenario":"The superintendent, touring your building, asks you directly: 'What's the biggest problem in your department right now?' Polishing the answer into a humblebrag wastes the question. Naming a real problem, with what you're doing about it, is what the moment is for.","task":"Write the spoken answer: the honest problem, its size, and your response to it in progress.","tips":["Name a real problem — leaders can tell a dodge from a disclosure instantly.","Attach the number that sizes it and the action already underway.","A named problem plus a plan reads as command; a denied problem reads as blindness."],"focus":["impact","precision"],"placeholder":"Honest answer: writing scores in grade 7 — down eight points over two years. We've rebuilt the feedback cycle this semester, and November's benchmark tells us if it's working."},
    {"id":"pressure-edu-mid-15","level":"mid","profession":"education","title":"The question outside your lane","scenario":"At the parent information night on curriculum, a parent asks you about the district's special-education legal obligations — specific, high-stakes, and genuinely not yours to answer. Winging it risks real harm; a bare 'not my area' strands the parent.","task":"Write the spoken response that declines to answer and routes the parent to the right person, warmly.","tips":["Say plainly it deserves an expert answer, not your best guess.","Route specifically: the name, the role, and how you'll connect them.","Take the handoff on yourself — 'I'll email her tonight and copy you.'"],"focus":["audience","clarity"],"placeholder":"That deserves a precise answer from the person who actually knows — our director of student services. I'll email her tonight and copy you so it doesn't drop."},
    {"id":"pressure-edu-mid-16","level":"mid","profession":"education","title":"Buying three seconds, honestly","scenario":"In the budget hearing, a board member asks a genuinely complex question about per-pupil costs across programs. You need a moment to structure the answer. There are honest ways to buy it — naming the question's parts back — and transparent stalls that fool no one.","task":"Write the spoken bridge you'd use: restating the question's parts, then beginning the answer.","tips":["Restate to structure, not to stall: 'that's really two questions — cost and outcome.'","One bridge per answer; two reads as filibuster.","Then actually answer the first part immediately — the bridge buys seconds, not minutes."],"focus":["structure","clarity"]},
    {"id":"pressure-edu-mid-17","level":"mid","profession":"education","title":"Wrong in front of everyone","scenario":"In the department meeting you state that the district requires a common final in all sections. A colleague pulls up the policy: it's recommended, not required. Twelve people watch you process being publicly wrong about the premise of your own agenda item.","task":"Write your spoken response in the moment.","tips":["Concede immediately and completely — 'you're right, I misread it' — no wriggle.","Then re-decide in the open: does the recommendation still deserve adoption? Make that case or drop it.","How you handle being wrong is watched more closely than being right ever is."],"focus":["clarity","impact"],"placeholder":"You're right — it's recommended, not required, and I stand corrected. So the real question for us: do we want it anyway? I think yes, and here's my case in one minute."},
    {"id":"pressure-edu-mid-18","level":"mid","profession":"education","title":"The number they want right now","scenario":"In the planning meeting, the principal pushes: 'Just give me a number — how much for the whole science-lab refresh?' Your real estimate needs two days of vendor quotes. A number said in this room becomes the number forever.","task":"Write the spoken response that gives a defensible range now and the firm number's arrival date.","tips":["Give the honest range with its ends explained, and label it an estimate out loud.","Anchor carefully: the number you say first is the one that gets remembered.","Commit to the firm figure by a date — that's what 'I need a number' usually means."],"focus":["precision","impact"],"placeholder":"Working range: $18,000 to $26,000, depending on whether we replace or refurbish the benches. Firm number with quotes by Thursday."},
    {"id":"pressure-edu-mid-19","level":"mid","profession":"education","title":"The student journalist's pointed question","scenario":"A student reporter for the school paper asks you, on the record: 'Teachers say the new schedule was decided without asking them. Is that true?' It's partially true — the committee had teacher reps, but the survey most teachers wanted never happened.","task":"Write the on-the-record answer: honest, precise, quotable without damage.","tips":["Answer the true part truthfully — students detect spin faster than adults.","Be precise about the process: what input happened, what didn't.","Speak in sentences you'd be comfortable reading in print, because you will."],"focus":["precision","audience"],"placeholder":"Partly true. Three teachers served on the committee, but the full-staff survey many wanted didn't happen — and that's fair criticism of the process."},
    {"id":"pressure-edu-mid-20","level":"mid","profession":"education","title":"'Why wasn't I told?'","scenario":"A colleague confronts you outside your room: she learned from a student that her course is moving rooms next year. She should have heard it from you — you knew Tuesday, planned to tell her at Friday's meeting, and the news outran you.","task":"Write your spoken response.","tips":["She's right on the substance — say so first, without qualifiers.","Explain the sequencing in one sentence; don't let the explanation eat the apology.","Give her the full picture now, plus how you'll handle the next one differently."],"focus":["clarity","audience"],"placeholder":"You're right — you should have heard it from me, and I'm sorry you didn't. I learned Tuesday and sat on it for Friday's meeting, which was the wrong call."},
    {"id":"pressure-edu-mid-21","level":"mid","profession":"education","title":"Three questions at once","scenario":"At the end of your PD session, a colleague stands and asks three questions in one breath: does this work for special education students, what about grading, and where's the time supposed to come from? Answering in a blur loses all three.","task":"Write the spoken response that triages the pile-up out loud and answers in order.","tips":["Name the three back: it shows you heard them and buys structure.","Answer the most consequential one first and fully.","It's fine to defer one — with a specific when and how."],"focus":["structure","concision"],"placeholder":"Three questions there — inclusion, grading, and time. Let me take inclusion first because it's the biggest one."},
    {"id":"pressure-edu-mid-22","level":"mid","profession":"education","title":"The parent in tears","scenario":"Mid-conference, a mother begins crying: 'I just don't know how to help him anymore.' The data on your table is suddenly beside the point. What she needs first is a human beat; what she needs second is one concrete, doable thing.","task":"Write your spoken response: the human acknowledgment, then the single next step.","tips":["Pause and acknowledge before any content — rushing past tears loses everything after.","Shrink the plan to one thing she can do this week, stated simply.","End with partnership: what you'll do on your side by when."],"focus":["audience","impact"],"placeholder":"This is hard, and the fact that you're here says a lot. Let's pick one thing for this week — just one — and I'll handle a matching piece at school."},
    {"id":"pressure-edu-mid-23","level":"mid","profession":"education","title":"'What would you do if it were your kid?'","scenario":"You've laid out the retention recommendation with data and options, and the father asks the question that cuts through all of it: 'What would you do if he were your son?' Deflecting to policy language now would cost you every ounce of trust built in the meeting.","task":"Write the spoken answer.","tips":["Answer it — the question deserves your actual judgment, owned as yours.","Ground it in the specifics of this child, not children in general.","You can be personal and professional in the same sentence; that's what he's asking for."],"focus":["impact","clarity"],"placeholder":"If he were mine, I'd choose the extra year — because of one thing I keep seeing: he has the ability, and he's running out of the time to use it."},
    {"id":"pressure-edu-mid-24","level":"mid","profession":"education","title":"Rapid-fire after the session","scenario":"Your PD session ends and six hands go up with four minutes left. Long answers now mean five people leave unanswered. The skill is the 20-second answer: direct response, one specific, and a pointer to more.","task":"Write your 20-second spoken answer to 'How do I start this with a class that's already checked out?'","tips":["Headline answer in the first sentence; one concrete example; where to find the rest.","Twenty seconds each serves six people; two minutes serves one.","'Find me afterward' is a real answer when offered specifically."],"focus":["concision","impact"],"placeholder":"Start smaller than feels useful — one two-minute routine, same time every day, for two weeks. Ask me after and I'll show you the one I'd pick for that group."},
    {"id":"pressure-edu-mid-25","level":"mid","profession":"education","title":"The false-premise question","scenario":"At the board meeting, a member asks: 'Since the department cut its writing instruction, what's the plan to restore it?' Writing instruction wasn't cut — it was restructured into every course, and total minutes went up. Answering 'the plan' would ratify a premise that's false.","task":"Write the spoken response that corrects the premise cleanly, then answers the real concern.","tips":["Correct the premise first, briefly and without scolding — then answer generously.","Give the number that replaces the false picture: minutes went up, not down.","The real concern under the question is 'is writing being taught?' — make sure you answer that one."],"focus":["precision","structure"],"placeholder":"One correction first: writing instruction wasn't cut — it moved into every course, and total writing minutes rose 20%. The fair question underneath is whether that's working, so here's the evidence."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-edu-mid-01","level":"mid","profession":"education","title":"The proposal as before-and-after","scenario":"Your curriculum proposal to the principal is a list of features: new texts, staged assessments, a portfolio. Features don't move decisions; change does. The real story: today, students write one big paper cold; after, they build it in drafts with feedback at every stage.","task":"Rewrite the proposal opening as a before/after in 3 sentences: where we are, where we could be, the bridge.","tips":["Paint the current state plainly enough to feel the problem.","The after-state is what students do differently, not what the binder contains.","The bridge is the proposal — one sentence, concrete."],"focus":["structure","impact"],"placeholder":"Today, our students write one high-stakes paper with feedback arriving only after the grade. Next year, they'd build that paper in three drafted stages, with feedback while it can still change the work."},
    {"id":"narrative-edu-mid-02","level":"mid","profession":"education","title":"The face of the pattern","scenario":"You are pitching a lunchtime homework club to the leadership team. Your data — 61 students with no quiet place to work at home — is solid and forgettable. You know one of those students: he does his homework in a parked car outside the library for the wifi.","task":"Write the 2-3 sentence pitch that pairs the number with the student.","tips":["Stakes become real when they have a face — one true, specific detail.","Keep the story to two sentences; its job is to make the number land, not replace it.","Anonymize with care and dignity; the student is a person, not a prop."],"focus":["impact","audience"],"placeholder":"Sixty-one of our students report having no quiet place to do homework. One of them spends evenings in a parked car outside the public library, using the wifi through the wall."},
    {"id":"narrative-edu-mid-03","level":"mid","profession":"education","title":"'We tried that in 2019'","scenario":"You're proposing peer observation rounds, and you already know the objection that will kill it in the room: the 2019 attempt collapsed in a month. If the objection lands before you address it, you're defending; if you name it first, you're leading.","task":"Write the part of your pitch that raises and answers the 2019 objection before anyone else can.","tips":["Name it yourself: 'the obvious objection is 2019 — let me take that head-on.'","Diagnose why it failed specifically, then show which conditions changed.","Preempting the strongest objection converts skeptics; dodging it creates them."],"focus":["structure","impact"],"placeholder":"The fair objection is 2019 — it collapsed in a month. It collapsed because it was mandatory and unscheduled. This version is voluntary, on the calendar, and covered."},
    {"id":"narrative-edu-mid-04","level":"mid","profession":"education","title":"Persuading the veteran","scenario":"You want your most experienced colleague to try structured retrieval starts in her classes. She's heard twenty initiatives come and go. Arguments from research bounce off; what might land is respect for her results plus one low-cost experiment framed on her terms.","task":"Write the 3-sentence spoken pitch tailored to her.","tips":["Open from her strength: this sharpens something she already does well.","Shrink the ask to a two-week experiment she controls and can quit.","Let her be the judge: 'run it and tell me if it's real' beats 'the research says.'"],"focus":["audience","impact"],"placeholder":"Your students already retain more than anyone's — I want to see what happens if we add one five-minute routine to that. Two weeks, your call at the end."},
    {"id":"narrative-edu-mid-05","level":"mid","profession":"education","title":"The budget ask you can see","scenario":"Your request for flexible seating funding says '$3,800 for modular classroom furniture.' The principal has read forty requests this month. None of them made her see a room: the winner will. You know exactly what changes — four fixed rows become six work zones students choose by task.","task":"Rewrite the ask so the reader can picture the room before and after.","tips":["Describe the scene, not the SKU: what a visitor sees at 10 a.m. in each version.","One sensory sentence per state is enough — then the number.","Requests that create a picture get remembered at decision time."],"focus":["impact","clarity"],"placeholder":"Right now, fourth period is 32 students facing forward in fixed rows regardless of the task. For $3,800, the same room becomes six zones — and students pick by what the work needs."},
    {"id":"narrative-edu-mid-06","level":"mid","profession":"education","title":"From pilot to program","scenario":"Your two-section writing pilot worked, and now you want it adopted grade-wide. The principal's unspoken question isn't 'did it work?' — it's 'will it survive contact with eight more teachers?' Your pitch must tell the scaling story, not re-argue the pilot.","task":"Write the 3-4 sentence pitch that moves from proven pilot to credible rollout.","tips":["One sentence of results; the rest is the scaling plan — that's where her doubt lives.","Name what breaks at scale (training, materials, buy-in) and your answer for each.","Propose a checkpoint that lets her say yes reversibly."],"focus":["structure","audience"],"placeholder":"The pilot's results held across both sections, so the question now is scale. Three things break when a pilot grows — training, materials, and buy-in — and here's the plan for each."},
    {"id":"narrative-edu-mid-07","level":"mid","profession":"education","title":"The later start time, sold to parents","scenario":"You're speaking at the community meeting in favor of the later school start. The research is on your side, but the room's real currency is mornings: carpools, work shifts, chaotic kitchens. A persuasive case starts inside their 7 a.m., not inside a sleep study.","task":"Write your 3-sentence spoken case pitched at the parents' actual morning.","tips":["Open in their world: the 6:45 wake-up battle they already hate.","Then the evidence, translated: what an extra 50 minutes does to a teenager's day.","Answer the logistics objection before the applause line — that's the vote you're winning."],"focus":["audience","impact"]},
    {"id":"narrative-edu-mid-08","level":"mid","profession":"education","title":"From scores to a decision","scenario":"You're presenting reading data to the board: grade 6 comprehension has slipped three years running. Data alone produces concerned nodding and no votes. The persuasive version ends somewhere specific: fund two interventionists, decide tonight, see the November checkpoint.","task":"Write the closing 3 sentences that turn the data into a decision request.","tips":["Data earns the right to ask; the ask still has to be made — explicitly.","Frame the decision as the bridge between the trend and the turnaround.","Name the checkpoint where they'll see whether their yes worked."],"focus":["impact","structure"],"placeholder":"Three years of decline is a trend, not a blip — and tonight is the decision point. Two reading interventionists, starting January, measured at the spring benchmark."},
    {"id":"narrative-edu-mid-09","level":"mid","profession":"education","title":"The schedule change, framed by gains","scenario":"The new schedule shortens your department's beloved double periods but adds a daily collaboration block. Your announcement draft leads with the loss and reads like a eulogy. Both facts are true; which one leads determines how the room receives the whole change.","task":"Write the 2-3 sentence announcement that frames the change around what teachers gain — without hiding the loss.","tips":["Lead with the gain that answers their oldest complaint: no shared planning time.","Name the loss honestly in the same breath — spin gets detected and resented.","Framing isn't deception; it's choosing which true thing sets the context."],"focus":["audience","clarity"],"placeholder":"Next year we finally get what we've asked for since I've been here: a daily shared planning block. The trade is real — double periods shrink to 70 minutes — and here's how the math nets out."},
    {"id":"narrative-edu-mid-10","level":"mid","profession":"education","title":"'Why now?'","scenario":"Your literacy proposal is strong, and the principal's likeliest response is still 'good idea — let's revisit in the fall.' Deferral is where good proposals go to die. The case for now exists: the vendor discount expires in June, and next year's sixth graders are this spring's decision.","task":"Write the 2-3 sentence urgency case that makes 'later' a decision with a cost.","tips":["'Later' feels free — your job is to price it: what waiting actually costs.","Tie now to a real clock: the discount, the schedule build, the cohort.","Urgency from facts persuades; urgency from adverbs annoys."],"focus":["impact","precision"],"placeholder":"Waiting until fall costs us two things we can count: the June vendor discount, and the entire incoming sixth-grade class — 210 kids who'd get the old program for a full year."},
    {"id":"narrative-edu-mid-11","level":"mid","profession":"education","title":"The analogy that carries","scenario":"You're explaining to families why the math program now spends weeks on fewer problems, worked deeply. 'Conceptual depth over procedural coverage' is true and dead on arrival. The right analogy — one from ordinary life — would do the work of three paragraphs.","task":"Write a 2-sentence explanation built on an analogy a parent would repeat at dinner.","tips":["Pick an analogy from their world: learning an instrument, a sport, cooking.","Test it for stretch: a good analogy survives one follow-up question.","If they repeat it to another parent accurately, it worked."],"focus":["audience","clarity"],"placeholder":"It's the difference between playing forty songs badly and learning five songs cold — the five-song kid can pick up anything later."},
    {"id":"narrative-edu-mid-12","level":"mid","profession":"education","title":"Two skeptics, one shared goal","scenario":"You're pairing two teachers for the co-teaching pilot and both are wary — one fears losing autonomy, the other fears being judged. Your pitch to them as a pair can't argue each fear separately; it needs a frame big enough to hold both: the section of 34 students neither can serve alone.","task":"Write the 3-sentence spoken pitch that reframes co-teaching around the shared problem.","tips":["Name the shared enemy: the problem neither can solve solo.","Address both fears in one structural promise: clear roles, no evaluation between partners.","End with the smallest committed step: one unit together, then reassess."],"focus":["audience","structure"]},
    {"id":"narrative-edu-mid-13","level":"mid","profession":"education","title":"The mentor recruitment ask","scenario":"You need six teachers to mentor next year's new hires. Your draft email lists duties and hours — a job posting no one will answer. The persuasive version tells them what they'd actually be doing: being the person they wish they'd had in year one.","task":"Rewrite the ask in 3 sentences that make the role worth wanting, with the real cost stated.","tips":["Lead with the meaning: everyone remembers their own year one.","State the true cost plainly — an undersold commitment collects resentment later.","Make the first step tiny: 'reply and I'll walk you through it Thursday.'"],"focus":["impact","audience"],"placeholder":"Think about who you needed in your first year — that's the job. It's real time: two hours a month, one observation each semester. If you're in, reply and I'll walk you through it Thursday."},
    {"id":"narrative-edu-mid-14","level":"mid","profession":"education","title":"The reluctant PD presenter","scenario":"Your strongest teacher runs the best discussions in the building, and she's declined to lead PD twice — 'I just teach, I don't present.' You want her to say yes. Flattery has failed. What might work: shrinking the stakes and reframing what presenting is.","task":"Write your 3-sentence spoken pitch to her.","tips":["Reframe: not a presentation — her fourth period, with colleagues watching the moves.","Shrink it: twenty minutes, one technique, you handle every slide and logistic.","Name the cost of her silence: everyone keeps reinventing what she's already solved."],"focus":["audience","impact"],"placeholder":"I'm not asking you to present — I'm asking you to show twenty minutes of what you already do fourth period. I'll handle every slide and logistic. Right now the whole department keeps reinventing what you've already solved."},
    {"id":"narrative-edu-mid-15","level":"mid","profession":"education","title":"Countering the decline story","scenario":"'The school isn't what it used to be' has taken hold among a vocal group of parents, stitched from one bad test year and a viral incident video. You can't refute a story with a spreadsheet. You need a truer story with the evidence woven in.","task":"Write the 3-4 sentence counter-narrative for the principal's newsletter.","tips":["Never repeat the negative frame to deny it — tell the truer story on its own terms.","Weave numbers into narrative: 'the class of 2025 earned more college credits than any before it.'","Concede the hard year inside the arc — a story with a setback is more believable than a highlight reel."],"focus":["impact","audience"],"placeholder":"This year's seniors earned more college credits than any class in school history — and they did it two years after our hardest year, which is the part that says the most."},
    {"id":"narrative-edu-mid-16","level":"mid","profession":"education","title":"The grant paragraph with stakes","scenario":"Your STEM-lab grant application draft says the funding would 'enhance hands-on learning opportunities.' Every application in the pile says that. Yours has something better: 140 students share 6 working microscopes, and biology labs run as demonstrations students watch.","task":"Rewrite the needs paragraph in 3 sentences with stakes a reviewer can see and feel.","tips":["The ratio is the story: 140 students, 6 microscopes — lead with it.","Show the consequence in the room: science as spectator sport.","End with the specific after-state the money buys."],"focus":["impact","precision"],"placeholder":"Our 140 biology students share six working microscopes, so labs run as demonstrations — science as a spectator sport. This grant makes it a contact sport: one working station per pair."},
    {"id":"narrative-edu-mid-17","level":"mid","profession":"education","title":"Selling revision to the class","scenario":"Tomorrow you hand back essay drafts and ask students to revise — historically the assignment they treat as punishment for not being done. You have ninety seconds at the start of class to reframe revision as the part where writers are actually made.","task":"Write the 3-4 sentence spoken pitch to a room of fifteen-year-olds.","tips":["Use their references: no athlete, artist, or game designer ships the first take.","Make the deal concrete: what the revision can earn, in grade and in skill.","Skip the lecture on growth mindset — show them the before/after of one real sentence."],"focus":["audience","impact"]},
    {"id":"narrative-edu-mid-18","level":"mid","profession":"education","title":"Disarming the phone-policy objection","scenario":"You're presenting the stricter phone policy at the staff meeting, and you know the strongest objection in the room — 'I use phones for instruction, this punishes good teaching' — belongs to the teachers you most need on board.","task":"Write the section of your pitch that raises and answers that objection before it's voiced.","tips":["State their objection better than they would — that's what earns the right to answer it.","Show the carve-out concretely: teacher-directed use stays, with the exact mechanism.","Answering the strongest objection first collapses the weaker ones behind it."],"focus":["structure","audience"],"placeholder":"The best objection in this room is 'I use phones to teach, and this punishes that.' So here's the carve-out, in writing: teacher-directed use is explicitly protected — what changes is only the default."},
    {"id":"narrative-edu-mid-19","level":"mid","profession":"education","title":"Ninety seconds with the superintendent","scenario":"The superintendent is touring your building Thursday and will spend ninety seconds in your department. You'll get one question — 'what are you working on?' — and one chance to make your literacy initiative exist in her mind when budget season comes.","task":"Write the 3-sentence spoken answer: the problem, the move, the early evidence.","tips":["Structure for memory: one problem, one move, one number.","Say the initiative's name twice — unnamed work can't be funded.","End one beat early; the impression of command comes from stopping."],"focus":["concision","impact"],"placeholder":"We found our seventh graders losing eight points in writing over two years, so we built the Drafting Cycle — every essay now gets feedback before the grade. First benchmark since launch: up five points."},
    {"id":"narrative-edu-mid-20","level":"mid","profession":"education","title":"One change, two stories","scenario":"The school is extending the day by 25 minutes for intervention. You must announce it twice: to staff (who hear 'longer day, same pay') and to families (who hear 'later pickup'). Same facts, two audiences, two different but honest framings.","task":"Write the opening 2 sentences of each version.","tips":["Each audience gets the benefit in their currency: staff get the duty trade, families get the tutoring their kids couldn't access.","Both versions must survive being seen by the other audience — honest framing, not double-speak.","The facts are identical; only the doorway changes."],"focus":["audience","structure"]},
    {"id":"narrative-edu-mid-21","level":"mid","profession":"education","title":"The concession that strengthens","scenario":"You're proposing the switch to standards-based report cards, and there's a real cost you've been tempted to soft-pedal: the first semester will be confusing for families, full stop. Hiding it invites ambush; owning it converts it into credibility.","task":"Write the 2-3 sentences of your pitch where you concede the cost and fold it into the case.","tips":["Concede at full strength — a minimized cost reads as either dishonesty or blindness.","Pair the concession with its mitigation in the same breath.","The speaker who names the downside owns the whole conversation about it."],"focus":["impact","clarity"],"placeholder":"Let me name the real cost: the first semester will confuse families — new format, new language, no sugarcoating it. That's why the rollout includes three things, starting with a translated guide mailed before report cards."},
    {"id":"narrative-edu-mid-22","level":"mid","profession":"education","title":"From gripe to proposal","scenario":"For a month, your department's lunch-table complaint has been the broken copier workflow: originals due 48 hours ahead, no priority queue before exams. Complaints change nothing. Written as a before/after proposal with a costed fix, the same grievance might.","task":"Convert the complaint into a 3-sentence written proposal to the operations manager.","tips":["Strip the grievance tone; describe the current state as neutral fact.","Quantify the pain once: hours lost, deadlines missed.","Propose the specific fix and its modest cost — complaint becomes plan."],"focus":["structure","impact"],"placeholder":"Under the current 48-hour copy policy, exam weeks reliably jam: last cycle, eleven teachers missed their window. A priority queue during the four exam weeks would fix it, at the cost of one aide-hour per day."},
    {"id":"narrative-edu-mid-23","level":"mid","profession":"education","title":"The three-year story","scenario":"Your department improvement plan opens with a bulleted list of nine goals. Nobody can want nine things. The plan is actually one story — from a department of solo artists to one that shares everything that works — and the nine bullets are chapters of it.","task":"Write the 3-sentence narrative overview that gives the nine goals one arc.","tips":["Find the single transformation underneath the goals and lead with it.","Sequence as a story: year one builds X, which makes year two's Y possible.","People fund and follow arcs, not lists — the bullets can live on page two."],"focus":["structure","impact"],"placeholder":"In three years, this department goes from ten strong classrooms to one strong program. Year one builds the shared assessment backbone; year two uses it to find and spread what works."},
    {"id":"narrative-edu-mid-24","level":"mid","profession":"education","title":"The testimonial and the number","scenario":"The after-school tutoring program is up for renewal, and you have two assets: a retention statistic (84% of enrolled students attended through the full semester) and a sentence from a parent's thank-you note. Either alone is dismissible. Together they're an argument.","task":"Write the 2-sentence renewal case that pairs them deliberately.","tips":["The number proves the pattern; the voice proves it matters — use both jobs.","Quote the parent's actual words; paraphrase kills testimony.","Order for a skeptical reader: statistic first, voice second."],"focus":["impact","precision"],"placeholder":"Eighty-four percent of enrolled students stayed through the full semester — for a voluntary after-school program, that's the number that matters. One parent wrote: 'It's the first year he asks to stay at school.'"},
    {"id":"narrative-edu-mid-25","level":"mid","profession":"education","title":"The close, asked out loud","scenario":"You've told the leadership team the whole story: the gap, the pilot, the evidence, the plan. Your prepared ending is 'so that's where we are.' Stories that end without an ask let the room decide the ending — and rooms default to 'interesting, let's revisit.'","task":"Write your final 2 spoken sentences: the story's conclusion and the explicit decision request.","tips":["The close restates the arc in one line — where we were, what changed.","Then the ask, with a date: approve the expansion for fall, decided by May 1.","Silence after the ask is your friend; resist filling it."],"focus":["impact","concision"],"placeholder":"A year ago this was a gap; today it's a working program with results in hand. I'm asking you to approve the fall expansion, with a decision by May 1 so it makes the schedule."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-edu-mid-01","level":"mid","profession":"education","title":"The observation that didn't go well","scenario":"You observed your mentee's lesson and it struggled: directions were unclear, transitions lost eight minutes, and the closing task didn't match the objective. Your drafted debrief opener spends four sentences on the decorated walls before approaching any of it.","task":"Write the debrief opening that names the headline honestly and kindly in the first two sentences.","tips":["Clear is kind: she can't fix what you won't name.","Lead with the most fixable big thing, stated as behavior, not character.","One genuine strength is honest context — four are anesthesia before a hidden needle."],"focus":["clarity","impact"],"placeholder":"I want to be straight with you: this lesson had real problems, and they're all fixable. The biggest one is directions — let's start there."},
    {"id":"hard-edu-mid-02","level":"mid","profession":"education","title":"The clean no to a colleague","scenario":"A colleague you like asked you to swap your planning period to cover her class every Thursday this semester so she can attend a course. You can't — that period is your only IEP-meeting window. Your draft reply is four sentences of throat-clearing around an unstated no.","task":"Write the reply: the no in sentence one, the reason in sentence two, an alternative if you have one.","tips":["A slow no wastes her time — she needs to find someone else today.","One true reason, stated once; three reasons read as excuses.","Offering a real alternative keeps the relationship without keeping the burden."],"focus":["clarity","concision"],"placeholder":"I can't take Thursdays — that period is my only window for IEP meetings, which I can't move. Two people who might: "},
    {"id":"hard-edu-mid-03","level":"mid","profession":"education","title":"The honors recommendation that isn't","scenario":"A parent has emailed asking you to recommend her daughter for honors English. The student is conscientious and struggling in the standard course — the recommendation wouldn't serve her. The kind-seeming dodge ('it's really a committee decision') just relocates the disappointment.","task":"Write the 3-4 sentence reply that declines clearly and gives the real, respectful reason.","tips":["The headline is the answer: you're not recommending honors this year.","Ground it in her interest: what the current course is building that honors would skip.","Name what would change your assessment — that's the honest door left open."],"focus":["clarity","audience"],"placeholder":"I'm not recommending Lena for honors this year, and I want to give you my real reasoning rather than a form answer."},
    {"id":"hard-edu-mid-04","level":"mid","profession":"education","title":"Announcing the program cut","scenario":"The district cut funding for the creative-writing elective your department fought to build, effective next year. You are announcing it at the department meeting. Your instinct is to open with fifteen minutes of budget context so the news lands 'softly.' It will land as dread instead.","task":"Write the announcement's first 3 sentences: the news, the reason, what survives.","tips":["Say it in sentence one — everyone senses bad news coming; delay is cruelty.","One sentence of honest reason, without performing the district's logic as your own.","Then what's preserved and what you fought for: that part is yours."],"focus":["clarity","impact"],"placeholder":"The creative-writing elective is cut for next year — the district pulled the funding line, and our appeal was denied. Here's what survives:"},
    {"id":"hard-edu-mid-05","level":"mid","profession":"education","title":"No to the principal","scenario":"The principal asked you to chair the accreditation committee on top of the department, the mentorship program, and the curriculum rewrite. Saying yes means doing all four badly. Your draft says 'I'm honored, and I'll figure out how to make it work.' That's a yes.","task":"Write the spoken response that declines, names the real constraint, and offers what you can do.","tips":["Decline the role, not the mission — offer the specific smaller piece you can own.","Name the tradeoff out loud: which current commitment the yes would break.","A no with reasons and an offer reads as judgment, not refusal."],"focus":["clarity","structure"],"placeholder":"I can't chair it and still deliver the curriculum rewrite — one of them would suffer, and honestly it'd be both. What I can do is own the self-study section."},
    {"id":"hard-edu-mid-06","level":"mid","profession":"education","title":"The behavior call nobody wants","scenario":"You have to call a parent about a real pattern: their daughter has mocked another student in class three times this week, documented each time. Last year this parent reacted badly to gentler versions. The temptation is to soften until the message dissolves.","task":"Write your opening 3 spoken sentences for the call.","tips":["State the behavior with dates — documented facts are kinder than characterizations.","Say the word for what it is; 'some social difficulties' protects no one, including her daughter.","Pair the hard message with the meeting you want: same team, one plan."],"focus":["clarity","audience"],"placeholder":"I'm calling about something specific: three times this week — Monday, Wednesday, and today — Priya mocked another student during class, and I documented each incident. I want us on the same team about this."},
    {"id":"hard-edu-mid-07","level":"mid","profession":"education","title":"The exam questions that miss","scenario":"A colleague submitted his share of the common exam and the questions have problems: two test material his sections covered but others didn't, and three are recall items where the blueprint calls for analysis. He drafted them in good faith. The exam assembles Thursday.","task":"Write the message that names the problems specifically and asks for the revision by the real deadline.","tips":["Specific and fixable: name the five questions and the two distinct issues.","Skip the compliment sandwich; a clear scope of fix is the respectful version.","State the deadline and offer the working session — critique plus help."],"focus":["precision","clarity"],"placeholder":"Five of your questions need revision before Thursday's assembly — two cover material only your sections saw, and three are recall where the blueprint calls for analysis. I can co-write replacements at lunch tomorrow."},
    {"id":"hard-edu-mid-08","level":"mid","profession":"education","title":"The volunteer who isn't working out","scenario":"A devoted parent volunteer has begun overstepping in your classroom: correcting students loudly, contradicting your instructions, drifting into other groups. Two soft redirects haven't landed. The kind path left is a direct conversation that resets the role or ends it.","task":"Write your spoken opening for that conversation.","tips":["Lead with the decision: the role is changing, effective now.","Name two concrete incidents, not a personality assessment.","Genuine gratitude belongs at the end, sized honestly — not as the anesthetic up front."],"focus":["clarity","audience"],"placeholder":"I need to reset how volunteering works in my room, starting today. Twice this week students got corrected in ways that crossed from helping into teaching — and that part has to be mine."},
    {"id":"hard-edu-mid-09","level":"mid","profession":"education","title":"The plagiarism call","scenario":"A strong student submitted an essay with two paragraphs lifted verbatim from a published review. Policy is clear: zero on the assignment, parent contact, documented report. You are calling a parent who will hear it as an attack on a good kid's future.","task":"Write your first 3 spoken sentences of the call.","tips":["State what happened and the evidence plainly — verbatim passages, source in hand.","Name the consequence as policy applied, not anger expressed.","Separate the act from the kid: the record is one assignment, not a verdict on character."],"focus":["clarity","precision"],"placeholder":"I need to tell you about something serious with Amir's essay: two paragraphs match a published review word for word — I have both in front of me. Per school policy, the essay receives a zero and this call is part of the process."},
    {"id":"hard-edu-mid-10","level":"mid","profession":"education","title":"Denying the grade appeal","scenario":"A student formally appealed her semester grade, and you've reviewed everything: the calculation stands. She's watching for whether the process was real. Your written denial needs to show the review actually happened — and close the question without inviting a rematch.","task":"Write the 3-4 sentence written response.","tips":["The decision first, then proof of genuine review: name what you rechecked.","Show the math once, concretely — that's what makes it feel fair.","Close with what's ahead, not an apology for the past: the door to next semester."],"focus":["clarity","structure"],"placeholder":"After a full review, the grade stands. I rechecked every entry, reweighted the categories by hand, and re-read your final essay against the rubric — the calculation comes out the same each way."},
    {"id":"hard-edu-mid-11","level":"mid","profession":"education","title":"The course that won't run","scenario":"Your colleague spent the spring designing a philosophy elective, and nine students enrolled — the minimum is fifteen. The course is cancelled for next year, and you're the one who has to tell him before he sees it on the master schedule.","task":"Write your spoken delivery: the news, the number, and what you want to preserve.","tips":["He should hear it from you before the schedule publishes — timing is part of the kindness.","The enrollment number is the reason; give it straight, no committee fog.","What's salvageable — a seminar unit, a spring retry with recruitment — is the second half, not a consolation mumble."],"focus":["clarity","impact"],"placeholder":"Philosophy isn't running next year — nine enrolled against the fifteen minimum, and I wanted you to hear it from me before the schedule posts. I have two ideas for keeping the work alive."},
    {"id":"hard-edu-mid-12","level":"mid","profession":"education","title":"The rating below expectations","scenario":"As part of the peer-evaluation cycle, you must deliver a 'developing' rating — below expectations — to a third-year teacher who believes the year went well. The rating is evidenced and fair. The meeting will only be useful if the headline arrives intact.","task":"Write your spoken opening 2-3 sentences of the evaluation conference.","tips":["Say the rating in the first sentence — she can't process anything said before it anyway.","Anchor to the two or three pieces of evidence, dated and specific.","The pivot to next steps is where the meeting should spend most of its minutes."],"focus":["clarity","structure"],"placeholder":"Your rating this cycle is 'developing,' which is below expectations, and I want to walk you through exactly why and exactly what changes it. The evidence centers on two areas."},
    {"id":"hard-edu-mid-13","level":"mid","profession":"education","title":"Cancelling the trip","scenario":"The eighth-grade capstone trip — paid for, planned, anticipated for months — is cancelled over a transportation safety issue that isn't fixable in time. You're writing the family message. Every soft opening you try reads as burying the one fact every reader is scanning for.","task":"Write the first 3 sentences of the family message.","tips":["Cancellation, reason, refund timeline: three facts, three sentences, top of the message.","The reason stated plainly builds more trust than reassuring adjectives.","What replaces it comes next — but only after the facts are fully landed."],"focus":["clarity","audience"],"placeholder":"The May 22 capstone trip is cancelled. Our charter company failed its safety inspection, and no alternative passed our vetting in time. Full refunds go out within two weeks."},
    {"id":"hard-edu-mid-14","level":"mid","profession":"education","title":"Telling the principal it failed","scenario":"The vocabulary program you championed — and convinced the principal to fund — didn't work: mid-year data shows no measurable gain over the comparison sections. She'll see the data eventually. The version of this where you bring it to her first is the only good version.","task":"Write your spoken opening: the result, your read, and your recommendation.","tips":["Lead with the flat result, unhedged — 'no measurable gain' is the sentence.","Your credibility survives failed pilots; it doesn't survive massaged data.","Bring the decision with you: kill it, fix it, or test it differently — recommend one."],"focus":["clarity","impact"],"placeholder":"The vocabulary pilot didn't work — mid-year data shows no measurable gain over the comparison sections. I recommend we stop it now and redirect the block, and here's what I think we salvage."},
    {"id":"hard-edu-mid-15","level":"mid","profession":"education","title":"No to the teacher-change demand","scenario":"A parent has demanded their son be moved out of a colleague's class, citing 'a personality clash.' You've reviewed it: the teacher's conduct is sound, the grade reflects the work, and policy doesn't support a move. The parent expects a yes and will escalate.","task":"Write the 3-4 sentence written response that says no clearly and holds a path forward.","tips":["The no comes first and stays unhedged — a soft no invites the appeal you're trying to prevent.","Ground it in what you reviewed, not in policy citations alone.","Offer the real next step: the three-way meeting that addresses the actual friction."],"focus":["clarity","audience"],"placeholder":"After reviewing the situation, I'm not moving Theo — the concerns don't support a section change. What I am proposing instead is a meeting with the three of us this week."},
    {"id":"hard-edu-mid-16","level":"mid","profession":"education","title":"The colleague who's always late","scenario":"A teacher on your hall has missed or arrived late to morning duty eleven times this quarter, and the aides have been covering silently. As department chair, this is yours to address directly before it becomes an administrative writeup.","task":"Write your spoken opening for the one-on-one.","tips":["Name the pattern with the count — eleven is a fact, 'often' is an accusation.","Skip the 'how's everything going' fake-out; she'll know why you asked to talk.","Ask the genuine question — what's happening? — after the facts, and mean it."],"focus":["clarity","precision"],"placeholder":"I need to raise something directly: morning duty — eleven misses or lates this quarter, and the aides have been absorbing it. What's going on?"},
    {"id":"hard-edu-mid-17","level":"mid","profession":"education","title":"The position that's going away","scenario":"Declining enrollment means your department loses a position next year; the newest teacher's contract won't renew. The decision is made and final. She's asked you point-blank in your office whether the rumors are true. HR's official letter is a week away.","task":"Write your spoken response.","tips":["Don't hide behind the HR timeline — she asked you a direct question in good faith.","Say what's true and what's yours to say: the position is cut, it's about enrollment, not her work.","Concrete help — the reference, the calls you'll make — is the only comfort worth offering."],"focus":["clarity","audience"],"placeholder":"I won't pretend: yes, the position is cut, and the official letter comes next week. This is enrollment math, not your teaching — and I'll put that in writing for anyone who calls me."},
    {"id":"hard-edu-mid-18","level":"mid","profession":"education","title":"She didn't get the role","scenario":"Your mentee applied for the lead-teacher role and interviewed well, but the committee chose a more experienced candidate. You're on the committee, and you're also the one she'll ask. She finds out officially tomorrow; she's asked to meet with you today.","task":"Write your spoken delivery: the outcome, the honest reason, and what her path is.","tips":["Give the outcome in the first sentence — she asked to meet because she suspects.","The real reason (experience gap, not performance) is the useful gift; vague comfort is not.","Name the specific development that changes the next decision, and your part in it."],"focus":["clarity","impact"],"placeholder":"You didn't get it — they chose Marcus, and the difference was years of grade-team leadership, not your interview or your teaching. Here's what closes that gap by next cycle."},
    {"id":"hard-edu-mid-19","level":"mid","profession":"education","title":"The grade that has to come down","scenario":"You found a spreadsheet error in your gradebook: a formula double-counted an assignment category, and four students' posted semester grades are wrong — including one whose A- becomes a B+. Families saw the posted grades. The correction email cannot hide what happened.","task":"Write the 3-4 sentence email to the affected family.","tips":["Own the error in the first sentence, in active voice: 'I made a calculation error.'","State the correction exactly: what was posted, what's accurate, why.","Explain the fix that prevents recurrence — that's the sentence that restores trust."],"focus":["clarity","precision"],"placeholder":"I made a calculation error in my gradebook, and Noor's corrected semester grade is a B+, not the A- that posted. A formula double-counted one category; I've verified every grade by hand since finding it."},
    {"id":"hard-edu-mid-20","level":"mid","profession":"education","title":"The safety conversation","scenario":"Walking past a colleague's chemistry lab, you saw students handling acids without goggles for the second time this month. He's senior to you and touchy about oversight. This can't wait for the friendly moment that never comes — someone's eyesight is the stake.","task":"Write your spoken opening for the direct conversation.","tips":["Safety outranks seniority and comfort — say what you saw, both dates.","Keep it about the specific practice, not his professionalism.","Be clear about what happens next if it continues; ambiguity here is complicity."],"focus":["clarity","impact"],"placeholder":"I have to raise something uncomfortable directly: twice this month — the 4th and today — I saw students handling acids in your lab without goggles. I need to know that stops now, or I'm obligated to take it further."},
    {"id":"hard-edu-mid-21","level":"mid","profession":"education","title":"The policy that won't bend","scenario":"A parent is on her fourth email asking you to accept her son's essay three weeks late without penalty, now citing family circumstances you've already accommodated once with a one-week extension. The answer is no. Each warm, lengthy reply you send has read as negotiation.","task":"Write the final reply: 3 sentences, kind and immovable.","tips":["Shorter is clearer: the fourth reply should be the shortest.","Restate the accommodation already made — it's the fairness receipt.","Close the loop explicitly: this is the final decision, and here's where his grade goes from here."],"focus":["concision","clarity"],"placeholder":"I understand the circumstances, which is why Daniel received the one-week extension. Beyond that, the late policy applies to everyone, and my decision is final. Here's what matters now: the next two assignments are worth more."},
    {"id":"hard-edu-mid-22","level":"mid","profession":"education","title":"Telling admin the load is too much","scenario":"The leadership team has launched three initiatives this semester — new LMS, new evaluation rubric, weekly data meetings — and your teachers are visibly drowning. As chair, you owe administration the upward hard message no one wants to send: something has to give.","task":"Write the 3-4 sentence message to the principal.","tips":["Lead with the claim, not the mood: the combined load is breaking implementation of all three.","Evidence over venting: one number or concrete example per initiative.","Recommend the specific sequencing — an upward hard message needs a proposal to land on."],"focus":["impact","structure"],"placeholder":"I need to flag something directly: the three concurrent rollouts are failing each other. My teachers are averaging four prep hours a week on systems, and LMS gradebook adoption is at half where it should be. I recommend we sequence:"},
    {"id":"hard-edu-mid-23","level":"mid","profession":"education","title":"The emails that are landing wrong","scenario":"A skilled teacher in your department writes emails to families that read as curt to the point of cold — three parents have mentioned it this semester. He has no idea; he thinks he's being efficient. Nobody has told him, which means everyone has decided you should.","task":"Write your spoken opening for the feedback conversation.","tips":["Name the gap between intent and effect — that's the whole message: efficient in, cold out.","Bring one real example and read it as a parent would.","Keep it fixable: two sentences of warmth per email is the actual ask."],"focus":["audience","clarity"],"placeholder":"I want to flag something you can't see from inside: your family emails read colder than you mean them. Three parents have mentioned it this semester — can I show you one and how it lands?"},
    {"id":"hard-edu-mid-24","level":"mid","profession":"education","title":"Ending the retake era","scenario":"After a year of data showing unlimited quiz retakes gutted first-attempt effort, the department voted to end them: one retake, corrections required. You're announcing it to students who have built their study habits — or absence of them — around the old rule.","task":"Write the 3-sentence spoken announcement to your classes.","tips":["The change first, in exact terms: one retake, corrections sheet required, starts Monday.","Give the real reason at student altitude — retakes were replacing studying, and the test data proved it.","Don't apologize for a decision the evidence made; explain it and hold."],"focus":["clarity","audience"],"placeholder":"Starting Monday, quiz retakes change: one retake per quiz, and you have to submit a corrections sheet first. Here's the honest reason: unlimited retakes taught this building to skip studying, and the final-exam data proved it."},
    {"id":"hard-edu-mid-25","level":"mid","profession":"education","title":"Owning the missed accommodation","scenario":"Reviewing a student's IEP for his annual meeting, you realize you've missed one of his accommodations all semester: he was entitled to extended time on every quiz and never got it. His grades are fine — but that's not the point, and his parents are entitled to hear it from you, plainly.","task":"Write the 3-4 sentence message to his parents.","tips":["Full ownership in sentence one: what was missed, for how long, by you.","No minimizing — 'his grades were fine anyway' is for them to conclude, not you to argue.","The remedy comes in the same message: the fix going forward and the offer to revisit affected quizzes."],"focus":["clarity","impact"],"placeholder":"I need to tell you about a mistake I made: Elias's IEP entitles him to extended time on quizzes, and I failed to provide it all semester. That's my error to own, and here's how I'm correcting it."}
  ],
  "putting-it-together": [
    {"id":"together-edu-mid-01","level":"mid","profession":"education","title":"The full incident email","scenario":"A lab incident this morning: two students ignored the procedure, a beaker broke, nobody was hurt, both students have consequences, and the lab resumes tomorrow with a re-taught safety protocol. One email to the families of everyone in the class must carry all of it — headline first, facts precise, tone steady.","task":"Write the complete 5-6 sentence email.","tips":["BLUF: incident, no injuries — in sentence one, because that's the only question every parent has.","Facts in order: what happened, what you did, what changes tomorrow.","Steady and specific throughout; alarm and vagueness are the twin failure modes."],"focus":["structure","audience"],"placeholder":"I'm writing about a lab incident in period 3 today — a beaker broke when procedure wasn't followed, and no one was hurt. Here's exactly what happened and what changes tomorrow."},
    {"id":"together-edu-mid-02","level":"mid","profession":"education","title":"Five minutes with the board","scenario":"You have five minutes on the board agenda to report on the intervention program: strong math results, flat reading results, a staffing request for next year. Every skill has to show up at once — headline, structure, precise numbers, calibrated ownership, and an explicit ask.","task":"Write your opening 4 sentences: headline, both results with numbers, and the ask.","tips":["Headline sentence carries the whole story: worked in math, not yet in reading, here's the ask.","Signpost the five minutes so the board can follow: results, then lesson, then request.","Precise numbers and one owned judgment — that combination is the presence."],"focus":["structure","impact"],"placeholder":"The intervention program delivered in math, hasn't yet in reading, and tonight I'm asking for one staffing change based on what we learned. First, the results: math up 11 points for participants; reading flat."},
    {"id":"together-edu-mid-03","level":"mid","profession":"education","title":"The one-page proposal","scenario":"Your curriculum proposal needs to survive three readers: the principal (cost and disruption), the curriculum director (standards alignment), and skeptical colleagues (workload). One page, recommendation first, strongest objection answered on the page. This is the memo version of everything you practice.","task":"Write the opening paragraph: recommendation, top two reasons, the named objection and its answer.","tips":["Recommendation in sentence one — every reader decides in the first paragraph whether to keep reading.","One reason aimed at each reader's actual question.","Naming the workload objection yourself is what earns the colleagues."],"focus":["structure","precision"],"placeholder":"I recommend we adopt the staged-portfolio writing model for grades 7-8 next fall. It costs nothing new, aligns to the revised standards we're already accountable for, and — the fair objection — adds grading time, which the attached calendar offsets by cutting two legacy assessments."},
    {"id":"together-edu-mid-04","level":"mid","profession":"education","title":"The crisis message","scenario":"A burst pipe flooded the east wing overnight. Twelve classrooms are closed for at least a week, six teachers are relocating by tomorrow morning, and families need to know what changes for their kids. You're drafting the family message for the principal's signature — under time pressure, with facts still moving.","task":"Write the 5-sentence family message.","tips":["Order by reader priority: is my kid affected, what changes, what stays the same.","Only verified facts get sentences; moving facts get 'update coming at 3 pm.'","Calm register, concrete nouns, zero filler — crisis writing is subtraction."],"focus":["audience","clarity"],"placeholder":"A burst pipe flooded the east wing overnight; school is open and every class will run. If your child has class in rooms 210-221, here's what changes tomorrow."},
    {"id":"together-edu-mid-05","level":"mid","profession":"education","title":"The year, in one page","scenario":"The principal wants each chair's end-of-year summary: results, misses, and next year's one priority — one page, due Friday. Your drafts keep swelling into narratives of everything that happened. The discipline is choosing: three results, one miss owned plainly, one priority argued for.","task":"Write the summary's opening 4 sentences: the year's headline, two results with numbers, the honest miss.","tips":["Headline the year the way you'd headline a finding: one sentence of verdict.","Numbers for the results, ownership for the miss — same steady voice for both.","The one priority should follow from the miss; that's what makes it a page and not a list."],"focus":["structure","concision"],"placeholder":"The department's year in one line: real gains in writing, a staffing problem we can no longer schedule around. Writing scores rose 7 points; AP enrollment grew from 94 to 118."},
    {"id":"together-edu-mid-06","level":"mid","profession":"education","title":"The reference that works","scenario":"Your strongest paraprofessional is applying to a teaching program and asked for a recommendation letter. Generic praise ('hardworking, great with kids') sinks these. What sells: two specific scenes and one precise claim about what she'll be like as a teacher — in under 250 words.","task":"Write the letter's opening paragraph: the claim, and the first specific scene as evidence.","tips":["Open with the calibrated claim you can defend: top-five-in-fifteen-years specific.","One scene, told concretely, outweighs six adjectives.","Write for a tired admissions reader: short sentences, front-loaded, real."],"focus":["impact","precision"],"placeholder":"In fifteen years I have worked with dozens of paraprofessionals; Renata is one of the three I would hire as a teacher tomorrow. One scene from October explains why."},
    {"id":"together-edu-mid-07","level":"mid","profession":"education","title":"Opening the IEP meeting","scenario":"You're leading the annual IEP meeting for a student whose year had real progress and one persistent gap. In the room: parents who are anxious, a case manager with paperwork, and forty-five scheduled minutes. Your two-minute opening sets whether this is a meeting or a formality.","task":"Write your spoken 4-sentence opening: the headline on his year, the agenda, and the parents' role named explicitly.","tips":["Lead with the honest headline — progress and the gap in the same sentence.","Signpost the 45 minutes so the parents know when their questions fit.","Naming their expertise ('you see what we can't') is structure, not flattery."],"focus":["structure","audience"],"placeholder":"Here's Mateo's year in one sentence: real progress in reading, and a writing gap that's still holding — and this meeting is where we adjust for that. We have 45 minutes and three things to cover."},
    {"id":"together-edu-mid-08","level":"mid","profession":"education","title":"The escalation with a paper trail","scenario":"After a semester of documented interventions — three parent contacts, a counselor referral, two behavior plans — a student's classroom behavior still endangers the learning of everyone else. Your escalation email to the assistant principal must compress the record, prove the process, and ask for the specific next step.","task":"Write the email's opening 3 sentences: the ask, the pattern in numbers, the documentation offered.","tips":["Lead with the ask — you want an administrative intervention meeting this week.","The numbers prove the process: three contacts, two plans, dates available.","Precision protects everyone here, including the student."],"focus":["structure","precision"],"placeholder":"I'm requesting an administrative intervention meeting for Cole this week — classroom-level options are exhausted. Since September: three documented parent contacts, a counselor referral, and two behavior plans, all with dates attached."},
    {"id":"together-edu-mid-09","level":"mid","profession":"education","title":"Ninety seconds for the pitch","scenario":"The leadership team gives each proposal ninety seconds at Thursday's meeting before questions. Yours is the peer-observation program: the problem, the design, the cost (two coverage periods a month), and the ask. Ninety seconds is about 200 words — every one has to earn its slot.","task":"Write the complete 90-second spoken pitch.","tips":["One sentence each: problem, solution, evidence it can work, cost, ask.","Cut every adjective that a number could replace.","End on the ask with a date, then stop — early finish reads as command."],"focus":["concision","impact"]},
    {"id":"together-edu-mid-10","level":"mid","profession":"education","title":"One change, three audiences","scenario":"The school is switching to a new gradebook portal over winter break. Teachers need training dates and migration steps; families need new login instructions; students need to know where assignments live. Three messages, one change — and each audience should get only their part.","task":"Write the first 2 sentences of each of the three messages.","tips":["Same fact, three doorways: each opening answers that reader's first question.","Resist the everything-email — routing is a communication skill.","Each version must be consistent with the others; audiences compare notes."],"focus":["audience","structure"]},
    {"id":"together-edu-mid-11","level":"mid","profession":"education","title":"The handoff document","scenario":"You're stepping down as chair in June, and your successor gets one document from you. Everything you know wants to be in it; what she needs is smaller: the three decisions coming at her before October, the two relationships to invest in first, and where every key file lives.","task":"Write the document's opening: the one-paragraph orientation that tells her how to read the rest.","tips":["Open with her first ninety days, not your last five years.","Order by when she'll need it — the October decisions outrank the history.","One honest sentence about the department's real dynamics is worth ten organizational charts."],"focus":["structure","audience"],"placeholder":"This document is ordered by when you'll need it: three decisions land before October, two relationships will make or break your first year, and everything else can wait for a coffee with me."},
    {"id":"together-edu-mid-12","level":"mid","profession":"education","title":"The grant's final report","scenario":"The foundation that funded your classroom-library grant requires a final report. They read hundreds; what they remember is one number and one moment. Yours: independent reading minutes doubled, and a specific student who read his first complete novel in March. The report paragraph must integrate both, precisely and warmly.","task":"Write the report's summary paragraph: outcome numbers, the one story, and what the funding permanently changed.","tips":["Numbers first for the program officer's spreadsheet, story second for her memory.","'Permanently changed' is the question funders actually ask — answer it explicitly.","Warm and precise are compatible; that's the whole craft."],"focus":["impact","precision"],"placeholder":"With this grant, independent reading time doubled — from 40 to 85 minutes weekly per student — and the shelf did the recruiting. In March, a ninth grader named for the report only as D. finished the first complete novel of his life."},
    {"id":"together-edu-mid-13","level":"mid","profession":"education","title":"The hardest conference","scenario":"Everything at once: you're recommending retention, the parents came in expecting a routine check-in, the data is solid, and the meeting is thirty minutes. Headline delivery, audience calibration, evidence precision, and the path forward all have to work together in your opening minute.","task":"Write your spoken opening 4 sentences.","tips":["The recommendation lands in the first two sentences — everything before it is unheard anyway.","Immediately anchor to shared purpose and evidence: this is about his next ten years, not this year's paperwork.","The plan gets more airtime than the verdict; structure the thirty minutes out loud."],"focus":["clarity","audience"],"placeholder":"I asked you here for something bigger than a check-in: I'm recommending Aiden repeat seventh grade, and I want to spend our thirty minutes on why and on the plan. This recommendation comes from a semester of data, and it's about setting up the next ten years, not judging this one."},
    {"id":"together-edu-mid-14","level":"mid","profession":"education","title":"A hundred words for the newsletter","scenario":"The family newsletter gives your department 100 words this month. You want to cover the poetry showcase (May 8, 6 pm, library), the AP exam window, and the summer reading list going live. Skimming parents on phones, hard word limit, three facts that matter — integration at miniature scale.","task":"Write the complete 100-word blurb.","tips":["Three items, one sentence or two each, most time-sensitive first.","Every sentence carries a date, a place, or an action — no throat-clearing.","Cut to fit by deleting clauses, not facts."],"focus":["concision","audience"],"placeholder":"Three things from the English department. First: the Poetry Showcase, May 8 at 6 pm in the library —"},
    {"id":"together-edu-mid-15","level":"mid","profession":"education","title":"The self-edit pass","scenario":"You wrote the staffing-request email to the principal in one draft: 340 words, request in paragraph three, two hedges per sentence, no numbers where numbers exist. Before sending, you run the full checklist on it — point first, audience fit, structure, cuts, precision, ownership.","task":"Write the edited version: 4 sentences that survive the checklist.","tips":["Find the ask in your draft and promote it to sentence one.","Replace every 'several' and 'significant' with its number.","Read it as the principal: what does she have to decide, and can she decide from this alone?"],"focus":["concision","structure"],"placeholder":"I'm requesting one additional English section for next year — a 0.4 FTE increase. Three of five current sections sit at 34 students against the contract cap of 32."},
    {"id":"together-edu-mid-16","level":"mid","profession":"education","title":"The budget answer with a spine","scenario":"At the board budget hearing, a member asks what your department would cut if forced to reduce 10%. The trap is mush; the moment calls for structure and ownership at once: your actual answer, its logic, and what you'd fight to protect — in under a minute, on the record.","task":"Write your spoken answer: the cut you'd recommend, the reasoning, the line you'd hold.","tips":["Answer the real question first — name what you'd cut, owned as your judgment.","One sentence of criteria shows it's reasoned, not random.","Naming what you'd protect and why is what makes it leadership on the record."],"focus":["impact","structure"],"placeholder":"If forced to 10%, I'd cut the elective sections before touching anything else — enrollment is softest there and no graduation requirement depends on them. The line I'd hold is intervention staffing."},
    {"id":"together-edu-mid-17","level":"mid","profession":"education","title":"The apology and the fix","scenario":"The grading portal published mid-semester grades a week early due to a settings error on your end — families saw volatile in-progress numbers, and eleven emails arrived overnight. Your message to all families must own it, explain what those numbers were, and fix the confusion — without a single defensive clause.","task":"Write the complete 4-5 sentence message.","tips":["Ownership, explanation, correction, prevention — in that order, no padding between.","Explain what the numbers meant precisely; the confusion is the actual damage.","One apology, placed early, sized right — then all business."],"focus":["clarity","structure"],"placeholder":"Mid-semester grades published a week early because of a settings error I made, and I'm sorry for the confusion overnight. What you saw were in-progress calculations with two major assignments not yet entered."},
    {"id":"together-edu-mid-18","level":"mid","profession":"education","title":"Two minutes at open house","scenario":"Open house night: families rotate through on a bell schedule, and you get two minutes of whole-room attention before the mingling starts. What they should leave holding: what their kids will make this year, how to reach you, and one way to help at home. Spoken, warm, structured, done.","task":"Write the complete two-minute welcome (about 5 sentences).","tips":["One vivid sentence about the year's work beats a curriculum overview.","The contact routine and the help-at-home tip must be concrete enough to survive the drive home.","Land the ending on time; the bell is part of the medium."],"focus":["audience","concision"]},
    {"id":"together-edu-mid-19","level":"mid","profession":"education","title":"State of the department","scenario":"Your August kickoff address to the department sets the year: last year's results in two numbers, this year's single priority, and what stays sacred amid the changes. Ten minutes, no slides, teachers who can smell filler from the parking lot.","task":"Write the opening 4 sentences of the address.","tips":["Open with the verdict on last year, numbers attached — respect starts with candor.","One priority, stated as one sentence, repeated once — two priorities is zero.","Name what won't change; stability is half of what a room needs to hear before change."],"focus":["structure","impact"],"placeholder":"Last year in two numbers: writing up seven points, and our widest-ever gap between sections — twelve points. This year has one priority: closing that gap section to section."},
    {"id":"together-edu-mid-20","level":"mid","profession":"education","title":"The hallway close","scenario":"You've requested a meeting about staffing twice; instead, the principal appears at your door: 'I've got about a minute — make your case.' Everything you'd have built across thirty minutes must compress into sixty seconds: the problem in numbers, the ask, the deadline, the consequence of waiting.","task":"Write the complete 60-second spoken case.","tips":["Skip all preamble — she granted the minute; spend it on content.","Four beats: problem number, specific ask, real deadline, cost of no.","Close by asking for the decision path: 'what do you need from me to say yes?'"],"focus":["concision","impact"],"placeholder":"Three of my five sections are over the contract cap, and it gets worse with next year's enrollment. I need one additional section — a 0.4 — approved before the master schedule locks March 15."},
    {"id":"together-edu-mid-21","level":"mid","profession":"education","title":"The observation write-up, complete","scenario":"Your formal write-up of a mentee's observed lesson goes into her file and to her evaluator. It must do everything at once: verifiable facts, your judgment labeled as such, growth priorities she can act on, and a fair overall picture — in four sentences she'll re-read many times.","task":"Write the complete 4-sentence summary.","tips":["Sentence of fact, sentence of labeled judgment, sentence of priority, sentence of trajectory.","Everything countable, counted; everything judged, owned.","Write it knowing three audiences read it: her, her evaluator, and her future self."],"focus":["precision","structure"],"placeholder":"Observed 2/12, period 4: objective posted and referenced twice, directions delivered before materials, 24 of 26 students on task through the practice block. My judgment: the strongest lesson of her three this year, driven by the tightened opening."},
    {"id":"together-edu-mid-22","level":"mid","profession":"education","title":"The June letter","scenario":"Your end-of-year letter to families closes out the year: what the class accomplished (concretely), one honest reflection, summer suggestions that won't be ignored, and a real goodbye for the students moving on. Warmth and structure have to hold each other up for one page.","task":"Write the letter's opening paragraph: the year's accomplishment in specifics, and the honest note.","tips":["Concrete accomplishments — the 61 essays, the two novels, the debate unit — beat 'so much growth.'","One honest note ('the spring slump was real, and here's what we learned') earns every warm sentence around it.","Write it as the last thing of yours they'll read; make the specifics do the feeling."],"focus":["audience","impact"],"placeholder":"This class wrote 61 essays this year, read two full novels, and argued fourteen formal debates — and in June you can see it: they write like people with something to say."},
    {"id":"together-edu-mid-23","level":"mid","profession":"education","title":"The sub plans that survive contact","scenario":"Tomorrow's emergency sub plans are the ultimate compression test: a stranger with no context must run your three preps, handle two students' accommodations, and get the one non-negotiable right — all from one page she'll read at 7:40 with students arriving at 8:00.","task":"Write the plan's opening: the one non-negotiable, then the first period's instructions in 3 lines.","tips":["Line one is the thing that cannot go wrong; everything else is numbered routine.","Write for 7:40 a.m. comprehension: short lines, bolded times, no pedagogy.","Each accommodation is an action with a name attached, not a document reference."],"focus":["clarity","structure"],"placeholder":"THE ONE THING: Period 4 takes the lab safety quiz at 11:15 — booklet in the red folder, no notes, collect all copies. Everything else below is routine."},
    {"id":"together-edu-mid-24","level":"mid","profession":"education","title":"Mixed results, full package","scenario":"Final presentation on the year-long homework redesign: completion rose 18%, achievement moved only 2 points, teacher opinion is split. The leadership team wants your recommendation, not a data recital. This is every module at once: headline, precision, calibration, narrative, ownership, ask.","task":"Write your spoken opening 4 sentences: headline with both numbers, your calibrated read, and the recommendation.","tips":["Both numbers in sentence one — leading with only the good one costs you the room.","Your calibrated read is the value-add: what the gap between the numbers means.","Recommend one path and name its risk yourself; that's the full skill stack in one move."],"focus":["precision","impact"],"placeholder":"The redesign moved behavior but not yet achievement: completion up 18%, scores up only 2 points. My read is that we fixed compliance and haven't yet fixed the quality of what's assigned — so I recommend we keep the structure and spend next year on task design."},
    {"id":"together-edu-mid-25","level":"mid","profession":"education","title":"Choose the channel, then deliver","scenario":"The department is eliminating class rank from transcripts — a sensitive change affecting juniors mid-stream. You must decide how it's communicated: all-family email, student assemblies, counselor one-on-ones for the affected top ten, or some sequence of these. The medium is the first sentence of the message.","task":"Name your channel sequence in one sentence, then write the first 3 sentences of the primary communication.","tips":["Sequence by stakes: the ten most-affected students hear it in person before any mass email lands.","Each channel gets the version its context can hold — assemblies carry rationale, email carries facts.","The channel decision is itself a communication skill; defend it in one clause."],"focus":["audience","structure"],"placeholder":"Sequence: counselor meetings for the top ten juniors Monday, grade assemblies Tuesday, family email Tuesday night. The email: 'Starting with this year's junior class, our transcripts will no longer include class rank.'"}
  ],
};
